LINUX_MAX_ERRNO = 4095
LINUX_ERR_PTR_MIN = ((-LINUX_MAX_ERRNO) & MASK64)


def _redacted_resolution_set(rows: dict[str, VerifiedResolution]) -> dict[str, dict[str, object]]:
    return {name: row.public_dict() for name, row in rows.items()}


def _is_kernel_err_ptr(value: int) -> bool:
    return (value & MASK64) >= LINUX_ERR_PTR_MIN


def _poke_bytes(session: ReplSession, runtime_vaddr: int, data: bytes) -> None:
    for offset in range(0, len(data), 8):
        chunk = data[offset:offset + 8]
        value = int.from_bytes(chunk.ljust(8, b"\x00"), "little")
        session.poke_runtime((runtime_vaddr + offset) & MASK64, value, 8)


def _peek_bytes(session: ReplSession, runtime_vaddr: int, length: int) -> bytes:
    out = bytearray()
    for offset in range(0, length, 8):
        value = session.peek_runtime((runtime_vaddr + offset) & MASK64, 8)
        out.extend(value.to_bytes(8, "little"))
    return bytes(out[:length])


def _run_call_proof_memcmp(session: ReplSession,
                           symbols: dict[str, Symbol],
                           image: StaticImage,
                           *,
                           alloc_size: int,
                           source_root: Path,
                           gfp: int,
                           gfp_components: dict[str, int]) -> tuple[dict[str, object], dict[str, object]]:
    scan_len = MEMCMP_PROOF_SIZE + MEMCMP_CANARY_LEN
    if alloc_size < scan_len:
        raise ReplError(f"memcmp call-proof alloc_size must be at least {scan_len} bytes")

    if MEMCMP_MISMATCH_OFFSET >= MEMCMP_PROOF_SIZE:
        raise ReplError("memcmp mismatch offset must be inside proof size")
    if MEMCMP_PROOF_BYTES[MEMCMP_MISMATCH_OFFSET] <= MEMCMP_MISMATCH_RIGHT_BYTE:
        raise ReplError("memcmp mismatch right byte must be less than left byte for positive sign proof")

    source = lookup_source_signature("memcmp", source_root=source_root)
    call_safety = require_call_safety_for_call(
        symbols,
        image,
        "memcmp",
        ("@owned_left_buffer", "@owned_right_buffer", MEMCMP_PROOF_SIZE),
    )
    if call_safety.get("tier") != CALL_PROOF_TARGETS["memcmp"]["expected_tier"]:
        raise ReplError("memcmp call-safety tier is not the expected vetted pointer tier")
    if not source.get("found") or source.get("pointer_arg_indices") != [0, 1]:
        raise ReplError("memcmp source signature does not declare x0/x1 as pointer arguments")

    resolutions = {
        "memcmp": resolve_verified(symbols, image, "memcmp", purpose="call", allow_pre_arg_deref=True),
        "__kmalloc": resolve_verified(symbols, image, "__kmalloc", purpose="call"),
        "kfree": resolve_verified(symbols, image, "kfree", purpose="call"),
    }
    memcmp_link = require_verified_resolution(resolutions["memcmp"], "call-proof target")
    kmalloc_link = require_verified_resolution(resolutions["__kmalloc"], "call-proof buffer allocator")
    kfree_link = require_verified_resolution(resolutions["kfree"], "call-proof buffer cleanup")
    assert_no_precall_x0_pointer_deref(image, kmalloc_link, "__kmalloc")

    right_mismatch = bytearray(MEMCMP_PROOF_BYTES)
    right_mismatch[MEMCMP_MISMATCH_OFFSET] = MEMCMP_MISMATCH_RIGHT_BYTE
    right_mismatch_bytes = bytes(right_mismatch)
    expected_left_scan = MEMCMP_PROOF_BYTES + (b"\xcc" * MEMCMP_CANARY_LEN)
    expected_right_equal_scan = expected_left_scan
    expected_right_mismatch_scan = right_mismatch_bytes + (b"\xcc" * MEMCMP_CANARY_LEN)

    checks: list[dict[str, object]] = [
        {
            "check": "static-c1-identity",
            "ok": True,
            "target": "memcmp",
            "resolution_method": resolutions["memcmp"].method,
        },
        {
            "check": "static-source-contract",
            "ok": True,
            "signature": source.get("selected", {}).get("signature")
            if isinstance(source.get("selected"), dict) else None,
            "pointer_arg_indices": source.get("pointer_arg_indices", []),
        },
        {
            "check": "static-call-safety-contract",
            "ok": True,
            "tier": call_safety.get("tier"),
            "required_valid_pointer_args": call_safety.get("required_valid_pointer_args", {}),
            "bounded_size": MEMCMP_PROOF_SIZE,
        },
    ]
    private: dict[str, object] = {}
    left_ptr = 0
    right_ptr = 0
    slide = 0
    kfree_runtime = 0
    free_attempted: list[str] = []
    free_ok: dict[str, bool] = {"left": False, "right": False}
    free_errors: list[str] = []
    equal_return = 0
    mismatch_return = 0
    observed_left = b""
    observed_right_equal = b""
    observed_right_mismatch = b""

    session.hide()
    session.set_panic_on_oops(0)
    try:
        slide = session.slide()
        if slide & 0xFFF:
            raise ReplError("slide is not page-aligned; refusing to proceed")
        memcmp_runtime = (memcmp_link + slide) & MASK64
        kmalloc_runtime = (kmalloc_link + slide) & MASK64
        kfree_runtime = (kfree_link + slide) & MASK64

        left_ptr = session.call_runtime(kmalloc_runtime, (alloc_size, gfp))
        right_ptr = session.call_runtime(kmalloc_runtime, (alloc_size, gfp))
        left_ok = is_kernel_lowmem_pointer(left_ptr)
        right_ok = is_kernel_lowmem_pointer(right_ptr)
        distinct_ok = left_ptr != right_ptr
        checks.append({
            "check": "kmalloc-owned-memcmp-buffers",
            "ok": left_ok and right_ok and distinct_ok,
            "alloc_size": alloc_size,
            "left_kernel_lowmem": left_ok,
            "right_kernel_lowmem": right_ok,
            "distinct_buffers": distinct_ok,
        })
        if not (left_ok and right_ok and distinct_ok):
            raise ReplError("__kmalloc did not return sane distinct memcmp buffers")

        _poke_bytes(session, left_ptr, expected_left_scan)
        _poke_bytes(session, right_ptr, expected_right_equal_scan)
        observed_left = _peek_bytes(session, left_ptr, scan_len)
        observed_right_equal = _peek_bytes(session, right_ptr, scan_len)
        setup_ok = observed_left == expected_left_scan and observed_right_equal == expected_right_equal_scan
        checks.append({
            "check": "owned-memcmp-buffer-poke-peek",
            "ok": setup_ok,
            "proof_bytes_label": MEMCMP_PROOF_BYTES.decode("ascii"),
            "size_arg": MEMCMP_PROOF_SIZE,
            "canary_len": MEMCMP_CANARY_LEN,
        })
        if not setup_ok:
            raise ReplError("owned memcmp buffer poke/peek mismatch")

        equal_return = session.call_runtime(memcmp_runtime, (left_ptr, right_ptr, MEMCMP_PROOF_SIZE))
        equal_ok = equal_return == 0
        checks.append({
            "check": "memcmp-equal-return-contract",
            "ok": equal_ok,
            "expected_return": "0x0",
            "observed_return": f"0x{equal_return:x}",
            "size_arg": MEMCMP_PROOF_SIZE,
        })
        if not equal_ok:
            raise ReplError(f"memcmp equal case returned 0x{equal_return:x}, expected 0")

        observed_left = _peek_bytes(session, left_ptr, scan_len)
        observed_right_equal = _peek_bytes(session, right_ptr, scan_len)
        equal_buffers_unchanged = observed_left == expected_left_scan and observed_right_equal == expected_right_equal_scan
        checks.append({
            "check": "memcmp-equal-buffer-immutability",
            "ok": equal_buffers_unchanged,
            "left_unchanged": observed_left == expected_left_scan,
            "right_unchanged": observed_right_equal == expected_right_equal_scan,
        })
        if not equal_buffers_unchanged:
            raise ReplError("memcmp equal case modified an owned buffer")

        _poke_bytes(session, right_ptr, expected_right_mismatch_scan)
        observed_right_mismatch = _peek_bytes(session, right_ptr, scan_len)
        mismatch_setup_ok = observed_right_mismatch == expected_right_mismatch_scan
        checks.append({
            "check": "owned-memcmp-mismatch-poke-peek",
            "ok": mismatch_setup_ok,
            "mismatch_offset": MEMCMP_MISMATCH_OFFSET,
            "left_byte": f"0x{MEMCMP_PROOF_BYTES[MEMCMP_MISMATCH_OFFSET]:02x}",
            "right_byte": f"0x{MEMCMP_MISMATCH_RIGHT_BYTE:02x}",
        })
        if not mismatch_setup_ok:
            raise ReplError("owned memcmp mismatch buffer poke/peek mismatch")

        mismatch_return = session.call_runtime(memcmp_runtime, (left_ptr, right_ptr, MEMCMP_PROOF_SIZE))
        mismatch_positive = 0 < mismatch_return < 0x80000000
        checks.append({
            "check": "memcmp-mismatch-return-contract",
            "ok": mismatch_positive,
            "expected_return_sign": "positive",
            "observed_return": f"0x{mismatch_return:x}",
            "mismatch_offset": MEMCMP_MISMATCH_OFFSET,
            "left_byte": f"0x{MEMCMP_PROOF_BYTES[MEMCMP_MISMATCH_OFFSET]:02x}",
            "right_byte": f"0x{MEMCMP_MISMATCH_RIGHT_BYTE:02x}",
        })
        if not mismatch_positive:
            raise ReplError(f"memcmp mismatch case returned 0x{mismatch_return:x}, expected positive int")

        observed_left = _peek_bytes(session, left_ptr, scan_len)
        observed_right_mismatch = _peek_bytes(session, right_ptr, scan_len)
        mismatch_buffers_unchanged = (
            observed_left == expected_left_scan
            and observed_right_mismatch == expected_right_mismatch_scan
        )
        checks.append({
            "check": "memcmp-mismatch-buffer-immutability",
            "ok": mismatch_buffers_unchanged,
            "left_unchanged": observed_left == expected_left_scan,
            "right_unchanged": observed_right_mismatch == expected_right_mismatch_scan,
        })
        if not mismatch_buffers_unchanged:
            raise ReplError("memcmp mismatch case modified an owned buffer")
    finally:
        if kfree_runtime:
            for label, ptr in (("left", left_ptr), ("right", right_ptr)):
                if ptr and is_kernel_lowmem_pointer(ptr):
                    free_attempted.append(label)
                    try:
                        session.call_runtime(kfree_runtime, (ptr,))
                        free_ok[label] = True
                    except Exception as exc:  # noqa: BLE001 - cleanup failures must be visible
                        free_errors.append(f"{label}:{exc}")
        session.set_panic_on_oops(1)

    cleanup_ok = bool(free_ok["left"] and free_ok["right"])
    checks.append({
        "check": "kfree-owned-memcmp-buffers",
        "ok": cleanup_ok,
        "free_attempted": free_attempted,
        "left_free_ok": free_ok["left"],
        "right_free_ok": free_ok["right"],
    })
    if free_errors:
        raise ReplError(f"kfree failed after memcmp proof: {free_errors}")

    passed = all(bool(check.get("ok")) for check in checks)
    summary = {
        "decision": f"a90-repl-live-call-proof-memcmp-{'pass' if passed else 'fail'}",
        "ok": passed,
        "target": "memcmp",
        "proof_status": "trusted-under-owned-input-contract" if passed else "failed",
        "input_contract": CALL_PROOF_TARGETS["memcmp"]["input_contract"],
        "return_contract": CALL_PROOF_TARGETS["memcmp"]["return_contract"],
        "alloc_size": alloc_size,
        "proof_bytes_label": MEMCMP_PROOF_BYTES.decode("ascii"),
        "size_arg": MEMCMP_PROOF_SIZE,
        "equal_expected_return_value": "0x0",
        "equal_observed_return_value": f"0x{equal_return:x}",
        "mismatch_expected_return_sign": "positive",
        "mismatch_observed_return_value": f"0x{mismatch_return:x}",
        "mismatch_offset": MEMCMP_MISMATCH_OFFSET,
        "mismatch_left_byte": f"0x{MEMCMP_PROOF_BYTES[MEMCMP_MISMATCH_OFFSET]:02x}",
        "mismatch_right_byte": f"0x{MEMCMP_MISMATCH_RIGHT_BYTE:02x}",
        "buffers_unchanged_after_calls": True,
        "gfp_kernel": f"0x{gfp:x}",
        "source_evidence": _source_row_evidence(source),
        "call_safety": call_safety,
        "resolutions": _redacted_resolution_set(resolutions),
        "raw_runtime_values_redacted": True,
        "owned_pointer_redacted": True,
        "observed_bytes_redacted": True,
        "checks": checks,
        "function_map_entry": {
            "symbol": "memcmp",
            "status": "live-proven",
            "trusted_input_contract": CALL_PROOF_TARGETS["memcmp"]["input_contract"],
            "return_contract": CALL_PROOF_TARGETS["memcmp"]["return_contract"],
            "observed_return_value": "equal=0x0,mismatch=positive",
            "cleanup": "kfree-owned-memcmp-buffers-ok" if cleanup_ok else "cleanup-failed",
            "auto_call_policy": "one-target-proof-only-not-mass-call",
        },
    }
    private.update({
        "slide": f"0x{slide:x}",
        "memcmp_runtime": f"0x{((memcmp_link + slide) & MASK64):x}",
        "left_ptr": f"0x{left_ptr:x}",
        "right_ptr": f"0x{right_ptr:x}",
        "left_bytes_hex": observed_left.hex(),
        "right_equal_bytes_hex": observed_right_equal.hex(),
        "right_mismatch_bytes_hex": observed_right_mismatch.hex(),
        "gfp_components": {key: f"0x{component:x}" for key, component in gfp_components.items()},
    })
    return summary, private


def _run_call_proof_memchr(session: ReplSession,
                           symbols: dict[str, Symbol],
                           image: StaticImage,
                           *,
                           alloc_size: int,
                           source_root: Path,
                           gfp: int,
                           gfp_components: dict[str, int]) -> tuple[dict[str, object], dict[str, object]]:
    scan_len = MEMCHR_PROOF_SIZE + MEMCHR_CANARY_LEN
    if alloc_size < scan_len:
        raise ReplError(f"memchr call-proof alloc_size must be at least {scan_len} bytes")
    if MEMCHR_EXPECTED_OFFSET < 0:
        raise ReplError("memchr proof buffer must contain the search byte")
    if MEMCHR_MISSING_BYTE in MEMCHR_PROOF_BYTES:
        raise ReplError("memchr missing-byte proof byte must not appear inside the bounded proof bytes")

    source = lookup_source_signature("memchr", source_root=source_root)
    call_safety = require_call_safety_for_call(
        symbols,
        image,
        "memchr",
        ("@owned_buffer", MEMCHR_SEARCH_BYTE, MEMCHR_PROOF_SIZE),
    )
    if call_safety.get("tier") != CALL_PROOF_TARGETS["memchr"]["expected_tier"]:
        raise ReplError("memchr call-safety tier is not the expected vetted pointer tier")
    if not source.get("found") or source.get("pointer_arg_indices") != [0]:
        raise ReplError("memchr source signature does not declare x0 as the buffer pointer argument")

    resolutions = {
        "memchr": resolve_verified(symbols, image, "memchr", purpose="call", allow_pre_arg_deref=True),
        "__kmalloc": resolve_verified(symbols, image, "__kmalloc", purpose="call"),
        "kfree": resolve_verified(symbols, image, "kfree", purpose="call"),
    }
    memchr_link = require_verified_resolution(resolutions["memchr"], "call-proof target")
    kmalloc_link = require_verified_resolution(resolutions["__kmalloc"], "call-proof buffer allocator")
    kfree_link = require_verified_resolution(resolutions["kfree"], "call-proof buffer cleanup")
    assert_no_precall_x0_pointer_deref(image, kmalloc_link, "__kmalloc")

    expected_scan = MEMCHR_PROOF_BYTES + MEMCHR_CANARY_BYTES
    checks: list[dict[str, object]] = [
        {
            "check": "static-c1-identity",
            "ok": True,
            "target": "memchr",
            "resolution_method": resolutions["memchr"].method,
        },
        {
            "check": "static-source-contract",
            "ok": True,
            "signature": source.get("selected", {}).get("signature")
            if isinstance(source.get("selected"), dict) else None,
            "pointer_arg_indices": source.get("pointer_arg_indices", []),
        },
        {
            "check": "static-call-safety-contract",
            "ok": True,
            "tier": call_safety.get("tier"),
            "required_valid_pointer_args": call_safety.get("required_valid_pointer_args", {}),
            "bounded_size": MEMCHR_PROOF_SIZE,
        },
    ]
    private: dict[str, object] = {}
    ptr = 0
    slide = 0
    kfree_runtime = 0
    free_ok = False
    free_error: str | None = None
    hit_return = 0
    missing_return = 0
    observed = b""

    session.hide()
    session.set_panic_on_oops(0)
    try:
        slide = session.slide()
        if slide & 0xFFF:
            raise ReplError("slide is not page-aligned; refusing to proceed")
        memchr_runtime = (memchr_link + slide) & MASK64
        kmalloc_runtime = (kmalloc_link + slide) & MASK64
        kfree_runtime = (kfree_link + slide) & MASK64

        ptr = session.call_runtime(kmalloc_runtime, (alloc_size, gfp))
        ptr_ok = is_kernel_lowmem_pointer(ptr)
        checks.append({
            "check": "kmalloc-owned-memchr-buffer",
            "ok": ptr_ok,
            "alloc_size": alloc_size,
            "kernel_lowmem": ptr_ok,
        })
        if not ptr_ok:
            raise ReplError("__kmalloc did not return a sane memchr buffer")

        _poke_bytes(session, ptr, expected_scan)
        observed = _peek_bytes(session, ptr, scan_len)
        setup_ok = observed == expected_scan
        checks.append({
            "check": "owned-memchr-buffer-poke-peek",
            "ok": setup_ok,
            "proof_bytes_label": MEMCHR_PROOF_BYTES.decode("ascii"),
            "size_arg": MEMCHR_PROOF_SIZE,
            "canary_len": MEMCHR_CANARY_LEN,
        })
        if not setup_ok:
            raise ReplError("owned memchr buffer poke/peek mismatch")

        hit_return = session.call_runtime(memchr_runtime, (ptr, MEMCHR_SEARCH_BYTE, MEMCHR_PROOF_SIZE))
        expected_hit_return = (ptr + MEMCHR_EXPECTED_OFFSET) & MASK64
        hit_ok = hit_return == expected_hit_return
        checks.append({
            "check": "memchr-hit-return-contract",
            "ok": hit_ok,
            "search_byte": f"0x{MEMCHR_SEARCH_BYTE:02x}",
            "expected_offset": MEMCHR_EXPECTED_OFFSET,
            "expected_return": "owned-buffer-pointer-plus-offset-redacted",
            "observed_return": "owned-buffer-pointer-plus-offset-redacted" if hit_ok else f"0x{hit_return:x}",
            "size_arg": MEMCHR_PROOF_SIZE,
        })
        if not hit_ok:
            raise ReplError(
                f"memchr hit returned 0x{hit_return:x}, expected owned pointer at offset {MEMCHR_EXPECTED_OFFSET}"
            )

        observed = _peek_bytes(session, ptr, scan_len)
        hit_unchanged = observed == expected_scan
        checks.append({
            "check": "memchr-hit-buffer-immutability",
            "ok": hit_unchanged,
            "buffer_unchanged": hit_unchanged,
        })
        if not hit_unchanged:
            raise ReplError("memchr hit case modified the owned buffer")

        missing_return = session.call_runtime(memchr_runtime, (ptr, MEMCHR_MISSING_BYTE, MEMCHR_PROOF_SIZE))
        missing_ok = missing_return == 0
        checks.append({
            "check": "memchr-missing-return-contract",
            "ok": missing_ok,
            "missing_byte": f"0x{MEMCHR_MISSING_BYTE:02x}",
            "expected_return": "0x0",
            "observed_return": f"0x{missing_return:x}",
            "bounded_canary_contains_missing_byte": True,
        })
        if not missing_ok:
            raise ReplError(f"memchr missing-byte case returned 0x{missing_return:x}, expected 0")

        observed = _peek_bytes(session, ptr, scan_len)
        missing_unchanged = observed == expected_scan
        checks.append({
            "check": "memchr-missing-buffer-immutability",
            "ok": missing_unchanged,
            "buffer_unchanged": missing_unchanged,
        })
        if not missing_unchanged:
            raise ReplError("memchr missing-byte case modified the owned buffer")
    finally:
        if kfree_runtime and ptr and is_kernel_lowmem_pointer(ptr):
            try:
                session.call_runtime(kfree_runtime, (ptr,))
                free_ok = True
            except Exception as exc:  # noqa: BLE001 - cleanup failures must be visible
                free_error = str(exc)
        session.set_panic_on_oops(1)

    checks.append({
        "check": "kfree-owned-memchr-buffer",
        "ok": free_ok,
        "free_attempted": bool(kfree_runtime and ptr),
    })
    if free_error:
        raise ReplError(f"kfree failed after memchr proof: {free_error}")

    passed = all(bool(check.get("ok")) for check in checks)
    summary = {
        "decision": f"a90-repl-live-call-proof-memchr-{'pass' if passed else 'fail'}",
        "ok": passed,
        "target": "memchr",
        "proof_status": "trusted-under-owned-input-contract" if passed else "failed",
        "input_contract": CALL_PROOF_TARGETS["memchr"]["input_contract"],
        "return_contract": CALL_PROOF_TARGETS["memchr"]["return_contract"],
        "alloc_size": alloc_size,
        "proof_bytes_label": MEMCHR_PROOF_BYTES.decode("ascii"),
        "size_arg": MEMCHR_PROOF_SIZE,
        "search_byte": f"0x{MEMCHR_SEARCH_BYTE:02x}",
        "expected_hit_offset": MEMCHR_EXPECTED_OFFSET,
        "hit_expected_return_value": "owned-buffer-pointer-plus-offset-redacted",
        "hit_observed_return_value": "owned-buffer-pointer-plus-offset-redacted",
        "hit_return_matches_expected_offset": hit_return == ((ptr + MEMCHR_EXPECTED_OFFSET) & MASK64),
        "missing_byte": f"0x{MEMCHR_MISSING_BYTE:02x}",
        "missing_expected_return_value": "0x0",
        "missing_observed_return_value": f"0x{missing_return:x}",
        "missing_return_matches_null": missing_return == 0,
        "canary_contains_missing_byte": True,
        "buffer_unchanged_after_calls": True,
        "gfp_kernel": f"0x{gfp:x}",
        "source_evidence": _source_row_evidence(source),
        "call_safety": call_safety,
        "resolutions": _redacted_resolution_set(resolutions),
        "raw_runtime_values_redacted": True,
        "owned_pointer_redacted": True,
        "observed_bytes_redacted": True,
        "checks": checks,
        "function_map_entry": {
            "symbol": "memchr",
            "status": "live-proven",
            "trusted_input_contract": CALL_PROOF_TARGETS["memchr"]["input_contract"],
            "return_contract": CALL_PROOF_TARGETS["memchr"]["return_contract"],
            "observed_return_value": f"hit-offset={MEMCHR_EXPECTED_OFFSET},missing=0x0",
            "cleanup": "kfree-owned-memchr-buffer-ok" if free_ok else "cleanup-failed",
            "auto_call_policy": "one-target-proof-only-not-mass-call",
        },
    }
    private.update({
        "slide": f"0x{slide:x}",
        "memchr_runtime": f"0x{((memchr_link + slide) & MASK64):x}",
        "alloc_ptr": f"0x{ptr:x}",
        "hit_return_ptr": f"0x{hit_return:x}",
        "missing_return_ptr": f"0x{missing_return:x}",
        "observed_bytes_hex": observed.hex(),
        "gfp_components": {key: f"0x{component:x}" for key, component in gfp_components.items()},
    })
    return summary, private


def _run_call_proof_memchr_inv(session: ReplSession,
                               symbols: dict[str, Symbol],
                               image: StaticImage,
                               *,
                               alloc_size: int,
                               source_root: Path,
                               gfp: int,
                               gfp_components: dict[str, int]) -> tuple[dict[str, object], dict[str, object]]:
    scan_len = MEMCHR_INV_PROOF_SIZE + MEMCHR_INV_CANARY_LEN
    if alloc_size < scan_len:
        raise ReplError(f"memchr_inv call-proof alloc_size must be at least {scan_len} bytes")
    if len(MEMCHR_INV_HIT_BYTES) != MEMCHR_INV_PROOF_SIZE:
        raise ReplError("memchr_inv hit proof bytes do not match proof size")
    if MEMCHR_INV_HIT_BYTES[MEMCHR_INV_EXPECTED_OFFSET] == MEMCHR_INV_FILL_BYTE:
        raise ReplError("memchr_inv expected offset must contain a non-fill byte")
    if any(byte != MEMCHR_INV_FILL_BYTE for byte in MEMCHR_INV_EQUAL_BYTES):
        raise ReplError("memchr_inv equal proof bytes must all match the fill byte")

    source = lookup_source_signature("memchr_inv", source_root=source_root)
    call_safety = require_call_safety_for_call(
        symbols,
        image,
        "memchr_inv",
        ("@owned_buffer", MEMCHR_INV_FILL_BYTE, MEMCHR_INV_PROOF_SIZE),
    )
    if call_safety.get("tier") != CALL_PROOF_TARGETS["memchr_inv"]["expected_tier"]:
        raise ReplError("memchr_inv call-safety tier is not the expected vetted pointer tier")
    if not source.get("found") or source.get("pointer_arg_indices") != [0]:
        raise ReplError("memchr_inv source signature does not declare x0 as the buffer pointer argument")

    resolutions = {
        "memchr_inv": resolve_verified(symbols, image, "memchr_inv", purpose="call", allow_pre_arg_deref=True),
        "__kmalloc": resolve_verified(symbols, image, "__kmalloc", purpose="call"),
        "kfree": resolve_verified(symbols, image, "kfree", purpose="call"),
    }
    memchr_inv_link = require_verified_resolution(resolutions["memchr_inv"], "call-proof target")
    kmalloc_link = require_verified_resolution(resolutions["__kmalloc"], "call-proof buffer allocator")
    kfree_link = require_verified_resolution(resolutions["kfree"], "call-proof buffer cleanup")
    assert_no_precall_x0_pointer_deref(image, kmalloc_link, "__kmalloc")

    expected_hit_scan = MEMCHR_INV_HIT_BYTES + MEMCHR_INV_CANARY_BYTES
    expected_equal_scan = MEMCHR_INV_EQUAL_BYTES + MEMCHR_INV_CANARY_BYTES
    checks: list[dict[str, object]] = [
        {
            "check": "static-c1-identity",
            "ok": True,
            "target": "memchr_inv",
            "resolution_method": resolutions["memchr_inv"].method,
        },
        {
            "check": "static-source-contract",
            "ok": True,
            "signature": source.get("selected", {}).get("signature")
            if isinstance(source.get("selected"), dict) else None,
            "pointer_arg_indices": source.get("pointer_arg_indices", []),
        },
        {
            "check": "static-call-safety-contract",
            "ok": True,
            "tier": call_safety.get("tier"),
            "required_valid_pointer_args": call_safety.get("required_valid_pointer_args", {}),
            "bounded_size": MEMCHR_INV_PROOF_SIZE,
        },
    ]
    private: dict[str, object] = {}
    ptr = 0
    slide = 0
    kfree_runtime = 0
    free_ok = False
    free_error: str | None = None
    hit_return = 0
    equal_return = 0
    observed_hit = b""
    observed_equal = b""

    session.hide()
    session.set_panic_on_oops(0)
    try:
        slide = session.slide()
        if slide & 0xFFF:
            raise ReplError("slide is not page-aligned; refusing to proceed")
        memchr_inv_runtime = (memchr_inv_link + slide) & MASK64
        kmalloc_runtime = (kmalloc_link + slide) & MASK64
        kfree_runtime = (kfree_link + slide) & MASK64

        ptr = session.call_runtime(kmalloc_runtime, (alloc_size, gfp))
        ptr_ok = is_kernel_lowmem_pointer(ptr)
        checks.append({
            "check": "kmalloc-owned-memchr-inv-buffer",
            "ok": ptr_ok,
            "alloc_size": alloc_size,
            "kernel_lowmem": ptr_ok,
        })
        if not ptr_ok:
            raise ReplError("__kmalloc did not return a sane memchr_inv buffer")

        _poke_bytes(session, ptr, expected_hit_scan)
        observed_hit = _peek_bytes(session, ptr, scan_len)
        hit_setup_ok = observed_hit == expected_hit_scan
        checks.append({
            "check": "owned-memchr-inv-hit-buffer-poke-peek",
            "ok": hit_setup_ok,
            "size_arg": MEMCHR_INV_PROOF_SIZE,
            "fill_byte": f"0x{MEMCHR_INV_FILL_BYTE:02x}",
            "expected_mismatch_offset": MEMCHR_INV_EXPECTED_OFFSET,
            "canary_len": MEMCHR_INV_CANARY_LEN,
        })
        if not hit_setup_ok:
            raise ReplError("owned memchr_inv hit buffer poke/peek mismatch")

        hit_return = session.call_runtime(
            memchr_inv_runtime,
            (ptr, MEMCHR_INV_FILL_BYTE, MEMCHR_INV_PROOF_SIZE),
        )
        expected_hit_return = (ptr + MEMCHR_INV_EXPECTED_OFFSET) & MASK64
        hit_ok = hit_return == expected_hit_return
        checks.append({
            "check": "memchr-inv-hit-return-contract",
            "ok": hit_ok,
            "fill_byte": f"0x{MEMCHR_INV_FILL_BYTE:02x}",
            "expected_offset": MEMCHR_INV_EXPECTED_OFFSET,
            "expected_return": "owned-buffer-pointer-plus-offset-redacted",
            "observed_return": "owned-buffer-pointer-plus-offset-redacted" if hit_ok else f"0x{hit_return:x}",
            "size_arg": MEMCHR_INV_PROOF_SIZE,
        })
        if not hit_ok:
            raise ReplError(
                "memchr_inv hit returned an unexpected pointer "
                f"(expected offset {MEMCHR_INV_EXPECTED_OFFSET})"
            )

        observed_hit = _peek_bytes(session, ptr, scan_len)
        hit_unchanged = observed_hit == expected_hit_scan
        checks.append({
            "check": "memchr-inv-hit-buffer-immutability",
            "ok": hit_unchanged,
            "buffer_unchanged": hit_unchanged,
        })
        if not hit_unchanged:
            raise ReplError("memchr_inv hit case modified the owned buffer")

        _poke_bytes(session, ptr, expected_equal_scan)
        observed_equal = _peek_bytes(session, ptr, scan_len)
        equal_setup_ok = observed_equal == expected_equal_scan
        checks.append({
            "check": "owned-memchr-inv-equal-buffer-poke-peek",
            "ok": equal_setup_ok,
            "size_arg": MEMCHR_INV_PROOF_SIZE,
            "canary_contains_non_fill_byte": True,
        })
        if not equal_setup_ok:
            raise ReplError("owned memchr_inv equal buffer poke/peek mismatch")

        equal_return = session.call_runtime(
            memchr_inv_runtime,
            (ptr, MEMCHR_INV_FILL_BYTE, MEMCHR_INV_PROOF_SIZE),
        )
        equal_ok = equal_return == 0
        checks.append({
            "check": "memchr-inv-all-fill-return-contract",
            "ok": equal_ok,
            "fill_byte": f"0x{MEMCHR_INV_FILL_BYTE:02x}",
            "expected_return": "0x0",
            "observed_return": f"0x{equal_return:x}",
            "bounded_canary_contains_non_fill_byte": True,
        })
        if not equal_ok:
            raise ReplError(f"memchr_inv all-fill case returned 0x{equal_return:x}, expected 0")

        observed_equal = _peek_bytes(session, ptr, scan_len)
        equal_unchanged = observed_equal == expected_equal_scan
        checks.append({
            "check": "memchr-inv-all-fill-buffer-immutability",
            "ok": equal_unchanged,
            "buffer_unchanged": equal_unchanged,
        })
        if not equal_unchanged:
            raise ReplError("memchr_inv all-fill case modified the owned buffer")
    finally:
        if kfree_runtime and ptr and is_kernel_lowmem_pointer(ptr):
            try:
                session.call_runtime(kfree_runtime, (ptr,))
                free_ok = True
            except Exception as exc:  # noqa: BLE001 - cleanup failures must be visible
                free_error = str(exc)
        session.set_panic_on_oops(1)

    checks.append({
        "check": "kfree-owned-memchr-inv-buffer",
        "ok": free_ok,
        "free_attempted": bool(kfree_runtime and ptr),
    })
    if free_error:
        raise ReplError(f"kfree failed after memchr_inv proof: {free_error}")

    passed = all(bool(check.get("ok")) for check in checks)
    summary = {
        "decision": f"a90-repl-live-call-proof-memchr_inv-{'pass' if passed else 'fail'}",
        "ok": passed,
        "target": "memchr_inv",
        "proof_status": "trusted-under-owned-input-contract" if passed else "failed",
        "input_contract": CALL_PROOF_TARGETS["memchr_inv"]["input_contract"],
        "return_contract": CALL_PROOF_TARGETS["memchr_inv"]["return_contract"],
        "alloc_size": alloc_size,
        "size_arg": MEMCHR_INV_PROOF_SIZE,
        "fill_byte": f"0x{MEMCHR_INV_FILL_BYTE:02x}",
        "mismatch_byte": f"0x{MEMCHR_INV_MISMATCH_BYTE:02x}",
        "expected_hit_offset": MEMCHR_INV_EXPECTED_OFFSET,
        "hit_expected_return_value": "owned-buffer-pointer-plus-offset-redacted",
        "hit_observed_return_value": "owned-buffer-pointer-plus-offset-redacted",
        "hit_return_matches_expected_offset": hit_return == ((ptr + MEMCHR_INV_EXPECTED_OFFSET) & MASK64),
        "all_fill_expected_return_value": "0x0",
        "all_fill_observed_return_value": f"0x{equal_return:x}",
        "all_fill_return_matches_null": equal_return == 0,
        "canary_contains_non_fill_byte": True,
        "buffer_unchanged_after_calls": True,
        "gfp_kernel": f"0x{gfp:x}",
        "source_evidence": _source_row_evidence(source),
        "call_safety": call_safety,
        "resolutions": _redacted_resolution_set(resolutions),
        "raw_runtime_values_redacted": True,
        "owned_pointer_redacted": True,
        "observed_bytes_redacted": True,
        "checks": checks,
        "function_map_entry": {
            "symbol": "memchr_inv",
            "status": "live-proven",
            "trusted_input_contract": CALL_PROOF_TARGETS["memchr_inv"]["input_contract"],
            "return_contract": CALL_PROOF_TARGETS["memchr_inv"]["return_contract"],
            "observed_return_value": f"hit-offset={MEMCHR_INV_EXPECTED_OFFSET},all-fill=0x0",
            "cleanup": "kfree-owned-memchr-inv-buffer-ok" if free_ok else "cleanup-failed",
            "auto_call_policy": "one-target-proof-only-not-mass-call",
        },
    }
    private.update({
        "slide": f"0x{slide:x}",
        "memchr_inv_runtime": f"0x{((memchr_inv_link + slide) & MASK64):x}",
        "alloc_ptr": f"0x{ptr:x}",
        "hit_return_ptr": f"0x{hit_return:x}",
        "all_fill_return_ptr": f"0x{equal_return:x}",
        "observed_hit_bytes_hex": observed_hit.hex(),
        "observed_equal_bytes_hex": observed_equal.hex(),
        "gfp_components": {key: f"0x{component:x}" for key, component in gfp_components.items()},
    })
    return summary, private


def _bitmap_complement_expected_bytes(nbits: int) -> bytes:
    if not (0 <= nbits <= BITMAP_COMPLEMENT_PROOF_SIZE_BITS):
        raise ReplError(f"invalid __bitmap_complement nbits {nbits}")

    src_words = [BITMAP_COMPLEMENT_SRC_WORD0, BITMAP_COMPLEMENT_SRC_WORD1]
    out_words = [BITMAP_COMPLEMENT_DST_INITIAL_WORD0, BITMAP_COMPLEMENT_DST_INITIAL_WORD1]
    full_words = nbits // 64
    tail_bits = nbits % 64
    for index in range(full_words):
        out_words[index] = (~src_words[index]) & MASK64
    if tail_bits:
        # This kernel's lib/bitmap.c complement path stores the whole tail word.
        out_words[full_words] = (~src_words[full_words]) & MASK64
    return b"".join(word.to_bytes(8, "little") for word in out_words)


def _bitmap_andnot_expected(mask_name: str, nbits: int) -> tuple[bytes, int]:
    if not (0 <= nbits <= BITMAP_ANDNOT_PROOF_SIZE_BITS):
        raise ReplError(f"invalid __bitmap_andnot nbits {nbits}")
    mask_words_by_name = {
        "partial": [BITMAP_ANDNOT_PARTIAL_MASK_WORD0, BITMAP_ANDNOT_PARTIAL_MASK_WORD1],
        "full": [BITMAP_ANDNOT_FULL_MASK_WORD0, BITMAP_ANDNOT_FULL_MASK_WORD1],
    }
    if mask_name not in mask_words_by_name:
        raise ReplError(f"unknown __bitmap_andnot mask {mask_name!r}")

    src_words = [BITMAP_ANDNOT_SRC_WORD0, BITMAP_ANDNOT_SRC_WORD1]
    mask_words = mask_words_by_name[mask_name]
    out_words = [BITMAP_ANDNOT_DST_INITIAL_WORD0, BITMAP_ANDNOT_DST_INITIAL_WORD1]
    accumulated = 0
    full_words = nbits // 64
    tail_bits = nbits % 64
    for index in range(full_words):
        out_words[index] = (src_words[index] & (~mask_words[index])) & MASK64
        accumulated |= out_words[index]
    if tail_bits:
        tail_mask = (1 << tail_bits) - 1
        out_words[full_words] = (
            src_words[full_words] & tail_mask & (~mask_words[full_words])
        ) & MASK64
        accumulated |= out_words[full_words]
    return b"".join(word.to_bytes(8, "little") for word in out_words), int(accumulated != 0)


def _bitmap_or_expected(right_name: str, nbits: int) -> bytes:
    if not (0 <= nbits <= BITMAP_OR_PROOF_SIZE_BITS):
        raise ReplError(f"invalid __bitmap_or nbits {nbits}")
    right_words_by_name = {
        "partial": [BITMAP_OR_RIGHT_PARTIAL_WORD0, BITMAP_OR_RIGHT_PARTIAL_WORD1],
        "full": [BITMAP_OR_RIGHT_FULL_WORD0, BITMAP_OR_RIGHT_FULL_WORD1],
    }
    if right_name not in right_words_by_name:
        raise ReplError(f"unknown __bitmap_or right bitmap {right_name!r}")

    left_words = [BITMAP_OR_LEFT_WORD0, BITMAP_OR_LEFT_WORD1]
    right_words = right_words_by_name[right_name]
    out_words = [BITMAP_OR_DST_INITIAL_WORD0, BITMAP_OR_DST_INITIAL_WORD1]
    nlongs = (nbits + 63) // 64
    for index in range(nlongs):
        out_words[index] = (left_words[index] | right_words[index]) & MASK64
    return b"".join(word.to_bytes(8, "little") for word in out_words)


def _bitmap_set_expected(start: int, length: int) -> bytes:
    if not (0 <= start <= BITMAP_SET_PROOF_SIZE_BITS):
        raise ReplError(f"invalid __bitmap_set start {start}")
    if not (0 <= length <= BITMAP_SET_PROOF_SIZE_BITS):
        raise ReplError(f"invalid __bitmap_set length {length}")
    if start + length > BITMAP_SET_PROOF_SIZE_BITS:
        raise ReplError(f"invalid __bitmap_set range {start}+{length}")

    out_words = [BITMAP_SET_INITIAL_WORD0, BITMAP_SET_INITIAL_WORD1]
    for bit in range(start, start + length):
        out_words[bit // 64] |= 1 << (bit % 64)
    return b"".join(word.to_bytes(8, "little") for word in out_words)


def _bitmap_clear_expected(start: int, length: int) -> bytes:
    if not (0 <= start <= BITMAP_CLEAR_PROOF_SIZE_BITS):
        raise ReplError(f"invalid __bitmap_clear start {start}")
    if not (0 <= length <= BITMAP_CLEAR_PROOF_SIZE_BITS):
        raise ReplError(f"invalid __bitmap_clear length {length}")
    if start + length > BITMAP_CLEAR_PROOF_SIZE_BITS:
        raise ReplError(f"invalid __bitmap_clear range {start}+{length}")

    out_words = [BITMAP_CLEAR_INITIAL_WORD0, BITMAP_CLEAR_INITIAL_WORD1]
    for bit in range(start, start + length):
        out_words[bit // 64] &= ~(1 << (bit % 64)) & MASK64
    return b"".join(word.to_bytes(8, "little") for word in out_words)


def _run_call_proof___bitmap_weight(session: ReplSession,
                                    symbols: dict[str, Symbol],
                                    image: StaticImage,
                                    *,
                                    alloc_size: int,
                                    source_root: Path,
                                    gfp: int,
                                    gfp_components: dict[str, int]) -> tuple[dict[str, object], dict[str, object]]:
    expected_scan = BITMAP_WEIGHT_BITMAP_BYTES + BITMAP_WEIGHT_CANARY_BYTES
    scan_len = len(expected_scan)
    if alloc_size < scan_len:
        raise ReplError(f"__bitmap_weight call-proof alloc_size must be at least {scan_len} bytes")
    if BITMAP_WEIGHT_PROOF_SIZE_BITS != len(BITMAP_WEIGHT_BITMAP_BYTES) * 8:
        raise ReplError("__bitmap_weight proof bit size does not match bitmap byte length")
    if any(bit < 0 or bit >= BITMAP_WEIGHT_PROOF_SIZE_BITS for bit in BITMAP_WEIGHT_ONE_BITS):
        raise ReplError("__bitmap_weight proof set bit is outside the bitmap")
    for label, nbits, expected in BITMAP_WEIGHT_CASES:
        if not (0 <= nbits <= BITMAP_WEIGHT_PROOF_SIZE_BITS):
            raise ReplError(f"__bitmap_weight case {label!r} has an invalid nbits")
        if not (0 <= expected <= nbits):
            raise ReplError(f"__bitmap_weight case {label!r} has an invalid expected return")

    source = lookup_source_signature("__bitmap_weight", source_root=source_root)
    call_safety = require_call_safety_for_call(
        symbols,
        image,
        "__bitmap_weight",
        ("@owned_bitmap_buffer", BITMAP_WEIGHT_PROOF_SIZE_BITS),
    )
    if call_safety.get("tier") != CALL_PROOF_TARGETS["__bitmap_weight"]["expected_tier"]:
        raise ReplError("__bitmap_weight call-safety tier is not the expected vetted pointer tier")
    selected = source.get("selected")
    selected_signature = selected.get("signature") if isinstance(selected, dict) else None
    if not source.get("found") or source.get("pointer_arg_indices") != [0]:
        raise ReplError("__bitmap_weight source signature does not declare x0 as the bitmap pointer argument")
    if selected_signature != CALL_PROOF_TARGETS["__bitmap_weight"]["source_signature"]:
        raise ReplError("__bitmap_weight source signature did not select the exported declaration")

    resolutions = {
        "__bitmap_weight": resolve_verified(
            symbols,
            image,
            "__bitmap_weight",
            purpose="call",
            allow_pre_arg_deref=True,
        ),
        "__kmalloc": resolve_verified(symbols, image, "__kmalloc", purpose="call"),
        "kfree": resolve_verified(symbols, image, "kfree", purpose="call"),
    }
    target_link = require_verified_resolution(resolutions["__bitmap_weight"], "call-proof target")
    kmalloc_link = require_verified_resolution(resolutions["__kmalloc"], "call-proof bitmap allocator")
    kfree_link = require_verified_resolution(resolutions["kfree"], "call-proof bitmap cleanup")
    assert_no_precall_x0_pointer_deref(image, kmalloc_link, "__kmalloc")

    full_word_bl = image.u32_at_vaddr(target_link + 0x38)
    tail_word_bl = image.u32_at_vaddr(target_link + 0x68)
    full_word_bl_ok = full_word_bl == BITMAP_WEIGHT_FULL_WORD_HWEIGHT64_BL_WORD
    tail_word_bl_ok = tail_word_bl == BITMAP_WEIGHT_TAIL_HWEIGHT64_BL_WORD

    checks: list[dict[str, object]] = [
        {
            "check": "static-c1-identity",
            "ok": True,
            "target": "__bitmap_weight",
            "resolution_method": resolutions["__bitmap_weight"].method,
        },
        {
            "check": "static-source-contract",
            "ok": True,
            "signature": selected_signature,
            "pointer_arg_indices": source.get("pointer_arg_indices", []),
        },
        {
            "check": "static-call-safety-contract",
            "ok": True,
            "tier": call_safety.get("tier"),
            "required_valid_pointer_args": call_safety.get("required_valid_pointer_args", {}),
            "bounded_size_bits": BITMAP_WEIGHT_PROOF_SIZE_BITS,
        },
        {
            "check": "static-full-word-hweight64-call",
            "ok": full_word_bl_ok,
            "expected_word": f"0x{BITMAP_WEIGHT_FULL_WORD_HWEIGHT64_BL_WORD:08x}",
            "observed_word": f"0x{full_word_bl:08x}",
        },
        {
            "check": "static-tail-word-hweight64-call",
            "ok": tail_word_bl_ok,
            "expected_word": f"0x{BITMAP_WEIGHT_TAIL_HWEIGHT64_BL_WORD:08x}",
            "observed_word": f"0x{tail_word_bl:08x}",
        },
    ]
    if not full_word_bl_ok:
        raise ReplError(
            "__bitmap_weight full-word path does not call the pinned __sw_hweight64 target "
            f"(word=0x{full_word_bl:08x})"
        )
    if not tail_word_bl_ok:
        raise ReplError(
            "__bitmap_weight tail-word path does not call the pinned __sw_hweight64 target "
            f"(word=0x{tail_word_bl:08x})"
        )

    private: dict[str, object] = {}
    ptr = 0
    slide = 0
    kfree_runtime = 0
    free_ok = False
    free_error: str | None = None
    observed = b""
    case_results: list[dict[str, object]] = []

    session.hide()
    session.set_panic_on_oops(0)
    try:
        slide = session.slide()
        if slide & 0xFFF:
            raise ReplError("slide is not page-aligned; refusing to proceed")
        target_runtime = (target_link + slide) & MASK64
        kmalloc_runtime = (kmalloc_link + slide) & MASK64
        kfree_runtime = (kfree_link + slide) & MASK64

        ptr = session.call_runtime(kmalloc_runtime, (alloc_size, gfp))
        ptr_ok = is_kernel_lowmem_pointer(ptr)
        checks.append({
            "check": "kmalloc-owned-bitmap-weight-bitmap",
            "ok": ptr_ok,
            "alloc_size": alloc_size,
            "kernel_lowmem": ptr_ok,
        })
        if not ptr_ok:
            raise ReplError("__kmalloc did not return a sane __bitmap_weight bitmap buffer")

        _poke_bytes(session, ptr, expected_scan)
        observed = _peek_bytes(session, ptr, scan_len)
        setup_ok = observed == expected_scan
        checks.append({
            "check": "owned-bitmap-weight-bitmap-poke-peek",
            "ok": setup_ok,
            "bitmap_size_bits": BITMAP_WEIGHT_PROOF_SIZE_BITS,
            "one_bits": list(BITMAP_WEIGHT_ONE_BITS),
            "canary_len": BITMAP_WEIGHT_CANARY_LEN,
        })
        if not setup_ok:
            raise ReplError("owned __bitmap_weight bitmap poke/peek mismatch")

        for label, nbits, expected in BITMAP_WEIGHT_CASES:
            observed_return = session.call_runtime(target_runtime, (ptr, nbits))
            ok = observed_return == expected
            case_results.append({
                "case": label,
                "nbits": nbits,
                "expected_return_value": f"0x{expected:x}",
                "observed_return_value": f"0x{observed_return:x}",
                "ok": ok,
            })
            if not ok:
                raise ReplError(
                    "__bitmap_weight "
                    f"{label} returned 0x{observed_return:x}, expected 0x{expected:x}"
                )

        observed = _peek_bytes(session, ptr, scan_len)
        unchanged = observed == expected_scan
        checks.append({
            "check": "bitmap-weight-bitmap-immutability",
            "ok": unchanged,
            "buffer_unchanged": unchanged,
            "canary_preserved": observed[-BITMAP_WEIGHT_CANARY_LEN:] == BITMAP_WEIGHT_CANARY_BYTES,
        })
        if not unchanged:
            raise ReplError("__bitmap_weight modified the owned bitmap buffer")
    finally:
        if kfree_runtime and ptr and is_kernel_lowmem_pointer(ptr):
            try:
                session.call_runtime(kfree_runtime, (ptr,))
                free_ok = True
            except Exception as exc:  # noqa: BLE001 - cleanup failures must be visible
                free_error = str(exc)
        session.set_panic_on_oops(1)

    checks.append({
        "check": "bitmap-weight-case-table",
        "ok": all(bool(case.get("ok")) for case in case_results),
        "case_count": len(case_results),
        "cases": case_results,
    })
    checks.append({
        "check": "kfree-owned-bitmap-weight-bitmap",
        "ok": free_ok,
        "free_attempted": bool(kfree_runtime and ptr),
    })
    if free_error:
        raise ReplError(f"kfree failed after __bitmap_weight proof: {free_error}")

    passed = all(bool(check.get("ok")) for check in checks)
    summary = {
        "decision": f"a90-repl-live-call-proof-__bitmap_weight-{'pass' if passed else 'fail'}",
        "ok": passed,
        "target": "__bitmap_weight",
        "proof_status": "trusted-under-owned-input-contract" if passed else "failed",
        "input_contract": CALL_PROOF_TARGETS["__bitmap_weight"]["input_contract"],
        "return_contract": CALL_PROOF_TARGETS["__bitmap_weight"]["return_contract"],
        "alloc_size": alloc_size,
        "bitmap_size_bits": BITMAP_WEIGHT_PROOF_SIZE_BITS,
        "one_bits": list(BITMAP_WEIGHT_ONE_BITS),
        "case_results": case_results,
        "bitmap_unchanged_after_calls": True,
        "gfp_kernel": f"0x{gfp:x}",
        "source_evidence": _source_row_evidence(source),
        "call_safety": call_safety,
        "resolutions": _redacted_resolution_set(resolutions),
        "raw_runtime_values_redacted": True,
        "owned_pointer_redacted": True,
        "observed_bytes_redacted": True,
        "checks": checks,
        "function_map_entry": {
            "symbol": "__bitmap_weight",
            "status": "live-proven",
            "trusted_input_contract": CALL_PROOF_TARGETS["__bitmap_weight"]["input_contract"],
            "return_contract": CALL_PROOF_TARGETS["__bitmap_weight"]["return_contract"],
            "observed_return_value": "case-table-zero-tail-full-popcount",
            "cleanup": "kfree-owned-bitmap-weight-bitmap-ok" if free_ok else "cleanup-failed",
            "auto_call_policy": "one-target-proof-only-not-mass-call",
        },
    }
    private.update({
        "slide": f"0x{slide:x}",
        "__bitmap_weight_runtime": f"0x{((target_link + slide) & MASK64):x}",
        "alloc_ptr": f"0x{ptr:x}",
        "observed_bytes_hex": observed.hex(),
        "case_returns": {
            str(case["case"]): str(case["observed_return_value"])
            for case in case_results
        },
        "gfp_components": {key: f"0x{component:x}" for key, component in gfp_components.items()},
    })
    return summary, private


def _run_call_proof___bitmap_complement(session: ReplSession,
                                        symbols: dict[str, Symbol],
                                        image: StaticImage,
                                        *,
                                        alloc_size: int,
                                        source_root: Path,
                                        gfp: int,
                                        gfp_components: dict[str, int]) -> tuple[dict[str, object], dict[str, object]]:
    src_scan = BITMAP_COMPLEMENT_SRC_BYTES + BITMAP_COMPLEMENT_CANARY_BYTES
    dst_initial_scan = BITMAP_COMPLEMENT_DST_INITIAL_BYTES + BITMAP_COMPLEMENT_CANARY_BYTES
    scan_len = len(src_scan)
    if alloc_size < scan_len:
        raise ReplError(f"__bitmap_complement call-proof alloc_size must be at least {scan_len} bytes")
    if BITMAP_COMPLEMENT_PROOF_SIZE_BITS != len(BITMAP_COMPLEMENT_SRC_BYTES) * 8:
        raise ReplError("__bitmap_complement proof bit size does not match bitmap byte length")
    if any(bit < 0 or bit >= BITMAP_COMPLEMENT_PROOF_SIZE_BITS for bit in BITMAP_COMPLEMENT_SRC_BITS):
        raise ReplError("__bitmap_complement proof set bit is outside the bitmap")
    for label, nbits in BITMAP_COMPLEMENT_CASES:
        if not (0 <= nbits <= BITMAP_COMPLEMENT_PROOF_SIZE_BITS):
            raise ReplError(f"__bitmap_complement case {label!r} has an invalid nbits")

    source = lookup_source_signature("__bitmap_complement", source_root=source_root)
    call_safety = require_call_safety_for_call(
        symbols,
        image,
        "__bitmap_complement",
        ("@owned_dst_bitmap", "@owned_src_bitmap", BITMAP_COMPLEMENT_PROOF_SIZE_BITS),
    )
    if call_safety.get("tier") != CALL_PROOF_TARGETS["__bitmap_complement"]["expected_tier"]:
        raise ReplError("__bitmap_complement call-safety tier is not the expected vetted pointer tier")
    selected = source.get("selected")
    selected_signature = selected.get("signature") if isinstance(selected, dict) else None
    if not source.get("found") or source.get("pointer_arg_indices") != [0, 1]:
        raise ReplError("__bitmap_complement source signature does not declare x0/x1 as bitmap pointer arguments")
    if selected_signature != CALL_PROOF_TARGETS["__bitmap_complement"]["source_signature"]:
        raise ReplError("__bitmap_complement source signature did not select the exported declaration")

    resolutions = {
        "__bitmap_complement": resolve_verified(
            symbols,
            image,
            "__bitmap_complement",
            purpose="call",
            allow_pre_arg_deref=True,
        ),
        "__kmalloc": resolve_verified(symbols, image, "__kmalloc", purpose="call"),
        "kfree": resolve_verified(symbols, image, "kfree", purpose="call"),
    }
    target_link = require_verified_resolution(resolutions["__bitmap_complement"], "call-proof target")
    kmalloc_link = require_verified_resolution(resolutions["__kmalloc"], "call-proof bitmap allocator")
    kfree_link = require_verified_resolution(resolutions["kfree"], "call-proof bitmap cleanup")
    assert_no_precall_x0_pointer_deref(image, kmalloc_link, "__kmalloc")

    static_words = {
        "lsr-nbits": (target_link + 0x00, BITMAP_COMPLEMENT_LSR_NBITS_WORD),
        "first-src-load": (target_link + 0x14, BITMAP_COMPLEMENT_FIRST_SRC_LOAD_WORD),
        "first-dst-store": (target_link + 0x24, BITMAP_COMPLEMENT_FIRST_DST_STORE_WORD),
        "tail-src-load": (target_link + 0x38, BITMAP_COMPLEMENT_TAIL_SRC_LOAD_WORD),
        "tail-dst-store": (target_link + 0x40, BITMAP_COMPLEMENT_TAIL_DST_STORE_WORD),
    }
    checks: list[dict[str, object]] = [
        {
            "check": "static-c1-identity",
            "ok": True,
            "target": "__bitmap_complement",
            "resolution_method": resolutions["__bitmap_complement"].method,
        },
        {
            "check": "static-source-contract",
            "ok": True,
            "signature": selected_signature,
            "pointer_arg_indices": source.get("pointer_arg_indices", []),
        },
        {
            "check": "static-call-safety-contract",
            "ok": True,
            "tier": call_safety.get("tier"),
            "required_valid_pointer_args": call_safety.get("required_valid_pointer_args", {}),
            "bounded_size_bits": BITMAP_COMPLEMENT_PROOF_SIZE_BITS,
        },
    ]
    for label, (vaddr, expected_word) in static_words.items():
        observed_word = image.u32_at_vaddr(vaddr)
        ok = observed_word == expected_word
        checks.append({
            "check": f"static-{label}",
            "ok": ok,
            "expected_word": f"0x{expected_word:08x}",
            "observed_word": f"0x{observed_word:08x}",
        })
        if not ok:
            raise ReplError(
                "__bitmap_complement static word mismatch for "
                f"{label}: observed 0x{observed_word:08x}, expected 0x{expected_word:08x}"
            )

    private: dict[str, object] = {}
    ptrs: dict[str, int] = {}
    slide = 0
    kfree_runtime = 0
    free_results: dict[str, bool] = {}
    free_errors: dict[str, str] = {}
    case_results: list[dict[str, object]] = []
    observed_dst_by_case: dict[str, bytes] = {}
    observed_src = b""

    session.hide()
    session.set_panic_on_oops(0)
    try:
        slide = session.slide()
        if slide & 0xFFF:
            raise ReplError("slide is not page-aligned; refusing to proceed")
        target_runtime = (target_link + slide) & MASK64
        kmalloc_runtime = (kmalloc_link + slide) & MASK64
        kfree_runtime = (kfree_link + slide) & MASK64

        for name, expected_scan in (("src", src_scan), ("dst", dst_initial_scan)):
            ptr = session.call_runtime(kmalloc_runtime, (alloc_size, gfp))
            ptr_ok = is_kernel_lowmem_pointer(ptr)
            checks.append({
                "check": f"kmalloc-owned-bitmap-complement-{name}",
                "ok": ptr_ok,
                "alloc_size": alloc_size,
                "kernel_lowmem": ptr_ok,
            })
            if not ptr_ok:
                raise ReplError(f"__kmalloc did not return a sane __bitmap_complement {name} buffer")
            ptrs[name] = ptr
            _poke_bytes(session, ptr, expected_scan)
            observed = _peek_bytes(session, ptr, scan_len)
            setup_ok = observed == expected_scan
            checks.append({
                "check": f"owned-bitmap-complement-{name}-poke-peek",
                "ok": setup_ok,
                "bitmap_size_bits": BITMAP_COMPLEMENT_PROOF_SIZE_BITS,
                "canary_len": BITMAP_COMPLEMENT_CANARY_LEN,
            })
            if not setup_ok:
                raise ReplError(f"owned __bitmap_complement {name} bitmap poke/peek mismatch")

        for label, nbits in BITMAP_COMPLEMENT_CASES:
            _poke_bytes(session, ptrs["dst"], dst_initial_scan)
            reset_dst = _peek_bytes(session, ptrs["dst"], scan_len)
            if reset_dst != dst_initial_scan:
                raise ReplError(f"owned __bitmap_complement dst reset mismatch before {label}")

            observed_return = session.call_runtime(target_runtime, (ptrs["dst"], ptrs["src"], nbits))
            expected_dst_scan = _bitmap_complement_expected_bytes(nbits) + BITMAP_COMPLEMENT_CANARY_BYTES
            observed_dst = _peek_bytes(session, ptrs["dst"], scan_len)
            observed_src = _peek_bytes(session, ptrs["src"], scan_len)
            dst_ok = observed_dst == expected_dst_scan
            src_ok = observed_src == src_scan
            canary_ok = (
                observed_dst[-BITMAP_COMPLEMENT_CANARY_LEN:] == BITMAP_COMPLEMENT_CANARY_BYTES
                and observed_src[-BITMAP_COMPLEMENT_CANARY_LEN:] == BITMAP_COMPLEMENT_CANARY_BYTES
            )
            observed_dst_by_case[label] = observed_dst
            case_results.append({
                "case": label,
                "nbits": nbits,
                "return_value_ignored": True,
                "observed_return_value_redacted": True,
                "dst_matches_expected": dst_ok,
                "src_unchanged": src_ok,
                "canary_preserved": canary_ok,
                "ok": dst_ok and src_ok and canary_ok,
            })
            if not dst_ok:
                raise ReplError(f"__bitmap_complement {label} dst bytes did not match expected complement")
            if not src_ok:
                raise ReplError(f"__bitmap_complement {label} modified the source bitmap")
            if not canary_ok:
                raise ReplError(f"__bitmap_complement {label} modified a canary")
            _ = observed_return
    finally:
        if kfree_runtime:
            for name, ptr in list(ptrs.items()):
                if ptr and is_kernel_lowmem_pointer(ptr):
                    try:
                        session.call_runtime(kfree_runtime, (ptr,))
                        free_results[name] = True
                    except Exception as exc:  # noqa: BLE001 - cleanup failures must be visible
                        free_results[name] = False
                        free_errors[name] = str(exc)
        session.set_panic_on_oops(1)

    checks.append({
        "check": "bitmap-complement-case-table",
        "ok": all(bool(case.get("ok")) for case in case_results),
        "case_count": len(case_results),
        "cases": case_results,
    })
    for name in ("src", "dst"):
        checks.append({
            "check": f"kfree-owned-bitmap-complement-{name}",
            "ok": free_results.get(name) is True,
            "free_attempted": name in ptrs,
        })
    if free_errors:
        detail = "; ".join(f"{name}: {msg}" for name, msg in sorted(free_errors.items()))
        raise ReplError(f"kfree failed after __bitmap_complement proof: {detail}")

    passed = all(bool(check.get("ok")) for check in checks)
    summary = {
        "decision": f"a90-repl-live-call-proof-__bitmap_complement-{'pass' if passed else 'fail'}",
        "ok": passed,
        "target": "__bitmap_complement",
        "proof_status": "trusted-under-owned-input-contract" if passed else "failed",
        "input_contract": CALL_PROOF_TARGETS["__bitmap_complement"]["input_contract"],
        "return_contract": CALL_PROOF_TARGETS["__bitmap_complement"]["return_contract"],
        "alloc_size": alloc_size,
        "bitmap_size_bits": BITMAP_COMPLEMENT_PROOF_SIZE_BITS,
        "src_bits": list(BITMAP_COMPLEMENT_SRC_BITS),
        "case_results": case_results,
        "dst_matches_expected_after_each_case": True,
        "src_unchanged_after_calls": True,
        "gfp_kernel": f"0x{gfp:x}",
        "source_evidence": _source_row_evidence(source),
        "call_safety": call_safety,
        "resolutions": _redacted_resolution_set(resolutions),
        "raw_runtime_values_redacted": True,
        "owned_pointer_redacted": True,
        "observed_bytes_redacted": True,
        "checks": checks,
        "function_map_entry": {
            "symbol": "__bitmap_complement",
            "status": "live-proven",
            "trusted_input_contract": CALL_PROOF_TARGETS["__bitmap_complement"]["input_contract"],
            "return_contract": CALL_PROOF_TARGETS["__bitmap_complement"]["return_contract"],
            "observed_return_value": "void-return-ignored-dst-case-table-complement",
            "cleanup": "kfree-owned-bitmap-complement-buffers-ok" if all(free_results.get(name) for name in ("src", "dst")) else "cleanup-failed",
            "auto_call_policy": "one-target-proof-only-not-mass-call",
        },
    }
    private.update({
        "slide": f"0x{slide:x}",
        "__bitmap_complement_runtime": f"0x{((target_link + slide) & MASK64):x}",
        "alloc_ptrs": {name: f"0x{ptr:x}" for name, ptr in ptrs.items()},
        "observed_bytes_hex": {
            "src": observed_src.hex(),
            "dst_by_case": {label: data.hex() for label, data in observed_dst_by_case.items()},
        },
        "gfp_components": {key: f"0x{component:x}" for key, component in gfp_components.items()},
    })
    return summary, private


def _run_call_proof___bitmap_andnot(session: ReplSession,
                                    symbols: dict[str, Symbol],
                                    image: StaticImage,
                                    *,
                                    alloc_size: int,
                                    source_root: Path,
                                    gfp: int,
                                    gfp_components: dict[str, int]) -> tuple[dict[str, object], dict[str, object]]:
    bitmap_payloads = {
        "src": BITMAP_ANDNOT_SRC_BYTES,
        "partial": BITMAP_ANDNOT_PARTIAL_MASK_BYTES,
        "full": BITMAP_ANDNOT_FULL_MASK_BYTES,
    }
    expected_scans = {
        name: payload + BITMAP_ANDNOT_CANARY_BYTES
        for name, payload in bitmap_payloads.items()
    }
    dst_initial_scan = BITMAP_ANDNOT_DST_INITIAL_BYTES + BITMAP_ANDNOT_CANARY_BYTES
    scan_len = len(dst_initial_scan)
    if alloc_size < scan_len:
        raise ReplError(f"__bitmap_andnot call-proof alloc_size must be at least {scan_len} bytes")
    if BITMAP_ANDNOT_PROOF_SIZE_BITS != len(BITMAP_ANDNOT_SRC_BYTES) * 8:
        raise ReplError("__bitmap_andnot proof bit size does not match bitmap byte length")
    if any(bit < 0 or bit >= BITMAP_ANDNOT_PROOF_SIZE_BITS for bit in BITMAP_ANDNOT_SRC_BITS):
        raise ReplError("__bitmap_andnot proof set bit is outside the bitmap")
    for label, mask_name, nbits, expected in BITMAP_ANDNOT_CASES:
        if mask_name not in ("partial", "full"):
            raise ReplError(f"__bitmap_andnot case {label!r} references an unknown mask")
        if not (0 <= nbits <= BITMAP_ANDNOT_PROOF_SIZE_BITS):
            raise ReplError(f"__bitmap_andnot case {label!r} has an invalid nbits")
        if expected not in (0, 1):
            raise ReplError(f"__bitmap_andnot case {label!r} has an invalid expected bool")
        _, computed = _bitmap_andnot_expected(mask_name, nbits)
        if computed != expected:
            raise ReplError(f"__bitmap_andnot case {label!r} expected bool disagrees with vector")

    source = lookup_source_signature("__bitmap_andnot", source_root=source_root)
    call_safety = require_call_safety_for_call(
        symbols,
        image,
        "__bitmap_andnot",
        ("@owned_dst_bitmap", "@owned_src_bitmap", "@owned_mask_bitmap", BITMAP_ANDNOT_PROOF_SIZE_BITS),
    )
    if call_safety.get("tier") != CALL_PROOF_TARGETS["__bitmap_andnot"]["expected_tier"]:
        raise ReplError("__bitmap_andnot call-safety tier is not the expected vetted pointer tier")
    selected = source.get("selected")
    selected_signature = selected.get("signature") if isinstance(selected, dict) else None
    if not source.get("found") or source.get("pointer_arg_indices") != [0, 1, 2]:
        raise ReplError("__bitmap_andnot source signature does not declare x0/x1/x2 as bitmap pointer arguments")
    if selected_signature != CALL_PROOF_TARGETS["__bitmap_andnot"]["source_signature"]:
        raise ReplError("__bitmap_andnot source signature did not select the exported declaration")

    resolutions = {
        "__bitmap_andnot": resolve_verified(
            symbols,
            image,
            "__bitmap_andnot",
            purpose="call",
            allow_pre_arg_deref=True,
        ),
        "__kmalloc": resolve_verified(symbols, image, "__kmalloc", purpose="call"),
        "kfree": resolve_verified(symbols, image, "kfree", purpose="call"),
    }
    target_link = require_verified_resolution(resolutions["__bitmap_andnot"], "call-proof target")
    kmalloc_link = require_verified_resolution(resolutions["__kmalloc"], "call-proof bitmap allocator")
    kfree_link = require_verified_resolution(resolutions["kfree"], "call-proof bitmap cleanup")
    assert_no_precall_x0_pointer_deref(image, kmalloc_link, "__kmalloc")

    static_words = {
        "lsr-nbits": (target_link + 0x00, BITMAP_ANDNOT_LSR_NBITS_WORD),
        "first-src-load": (target_link + 0x1C, BITMAP_ANDNOT_FIRST_SRC_LOAD_WORD),
        "first-mask-load": (target_link + 0x20, BITMAP_ANDNOT_FIRST_MASK_LOAD_WORD),
        "first-bic": (target_link + 0x24, BITMAP_ANDNOT_FIRST_BIC_WORD),
        "first-dst-store": (target_link + 0x34, BITMAP_ANDNOT_FIRST_DST_STORE_WORD),
        "tail-src-load": (target_link + 0x50, BITMAP_ANDNOT_TAIL_SRC_LOAD_WORD),
        "tail-mask-load": (target_link + 0x54, BITMAP_ANDNOT_TAIL_MASK_LOAD_WORD),
        "tail-dst-store": (target_link + 0x68, BITMAP_ANDNOT_TAIL_DST_STORE_WORD),
        "return-cset": (target_link + 0x70, BITMAP_ANDNOT_RETURN_CSET_WORD),
    }
    checks: list[dict[str, object]] = [
        {
            "check": "static-c1-identity",
            "ok": True,
            "target": "__bitmap_andnot",
            "resolution_method": resolutions["__bitmap_andnot"].method,
        },
        {
            "check": "static-source-contract",
            "ok": True,
            "signature": selected_signature,
            "pointer_arg_indices": source.get("pointer_arg_indices", []),
        },
        {
            "check": "static-call-safety-contract",
            "ok": True,
            "tier": call_safety.get("tier"),
            "required_valid_pointer_args": call_safety.get("required_valid_pointer_args", {}),
            "bounded_size_bits": BITMAP_ANDNOT_PROOF_SIZE_BITS,
        },
    ]
    for label, (vaddr, expected_word) in static_words.items():
        observed_word = image.u32_at_vaddr(vaddr)
        ok = observed_word == expected_word
        checks.append({
            "check": f"static-{label}",
            "ok": ok,
            "expected_word": f"0x{expected_word:08x}",
            "observed_word": f"0x{observed_word:08x}",
        })
        if not ok:
            raise ReplError(
                "__bitmap_andnot static word mismatch for "
                f"{label}: observed 0x{observed_word:08x}, expected 0x{expected_word:08x}"
            )

    private: dict[str, object] = {}
    ptrs: dict[str, int] = {}
    slide = 0
    kfree_runtime = 0
    free_results: dict[str, bool] = {}
    free_errors: dict[str, str] = {}
    case_results: list[dict[str, object]] = []
    observed_dst_by_case: dict[str, bytes] = {}
    observed_after: dict[str, bytes] = {}

    session.hide()
    session.set_panic_on_oops(0)
    try:
        slide = session.slide()
        if slide & 0xFFF:
            raise ReplError("slide is not page-aligned; refusing to proceed")
        target_runtime = (target_link + slide) & MASK64
        kmalloc_runtime = (kmalloc_link + slide) & MASK64
        kfree_runtime = (kfree_link + slide) & MASK64

        for name, expected_scan in (("src", expected_scans["src"]), ("partial", expected_scans["partial"]), ("full", expected_scans["full"]), ("dst", dst_initial_scan)):
            ptr = session.call_runtime(kmalloc_runtime, (alloc_size, gfp))
            ptr_ok = is_kernel_lowmem_pointer(ptr)
            checks.append({
                "check": f"kmalloc-owned-bitmap-andnot-{name}",
                "ok": ptr_ok,
                "alloc_size": alloc_size,
                "kernel_lowmem": ptr_ok,
            })
            if not ptr_ok:
                raise ReplError(f"__kmalloc did not return a sane __bitmap_andnot {name} buffer")
            ptrs[name] = ptr
            _poke_bytes(session, ptr, expected_scan)
            observed = _peek_bytes(session, ptr, scan_len)
            setup_ok = observed == expected_scan
            checks.append({
                "check": f"owned-bitmap-andnot-{name}-poke-peek",
                "ok": setup_ok,
                "bitmap_size_bits": BITMAP_ANDNOT_PROOF_SIZE_BITS,
                "canary_len": BITMAP_ANDNOT_CANARY_LEN,
            })
            if not setup_ok:
                raise ReplError(f"owned __bitmap_andnot {name} bitmap poke/peek mismatch")

        for label, mask_name, nbits, expected_return in BITMAP_ANDNOT_CASES:
            _poke_bytes(session, ptrs["dst"], dst_initial_scan)
            reset_dst = _peek_bytes(session, ptrs["dst"], scan_len)
            if reset_dst != dst_initial_scan:
                raise ReplError(f"owned __bitmap_andnot dst reset mismatch before {label}")

            expected_dst_bytes, computed_return = _bitmap_andnot_expected(mask_name, nbits)
            if computed_return != expected_return:
                raise ReplError(f"__bitmap_andnot {label} computed return disagrees with case table")
            observed_return = session.call_runtime(
                target_runtime,
                (ptrs["dst"], ptrs["src"], ptrs[mask_name], nbits),
            )
            expected_dst_scan = expected_dst_bytes + BITMAP_ANDNOT_CANARY_BYTES
            observed_dst = _peek_bytes(session, ptrs["dst"], scan_len)
            observed_src = _peek_bytes(session, ptrs["src"], scan_len)
            observed_mask = _peek_bytes(session, ptrs[mask_name], scan_len)
            dst_ok = observed_dst == expected_dst_scan
            src_ok = observed_src == expected_scans["src"]
            mask_ok = observed_mask == expected_scans[mask_name]
            canary_ok = (
                observed_dst[-BITMAP_ANDNOT_CANARY_LEN:] == BITMAP_ANDNOT_CANARY_BYTES
                and observed_src[-BITMAP_ANDNOT_CANARY_LEN:] == BITMAP_ANDNOT_CANARY_BYTES
                and observed_mask[-BITMAP_ANDNOT_CANARY_LEN:] == BITMAP_ANDNOT_CANARY_BYTES
            )
            return_ok = observed_return == expected_return
            observed_dst_by_case[label] = observed_dst
            case_results.append({
                "case": label,
                "mask": mask_name,
                "nbits": nbits,
                "expected_return_value": f"0x{expected_return:x}",
                "observed_return_value": f"0x{observed_return:x}",
                "dst_matches_expected": dst_ok,
                "src_unchanged": src_ok,
                "mask_unchanged": mask_ok,
                "canary_preserved": canary_ok,
                "ok": return_ok and dst_ok and src_ok and mask_ok and canary_ok,
            })
            if not return_ok:
                raise ReplError(
                    "__bitmap_andnot "
                    f"{label} returned 0x{observed_return:x}, expected 0x{expected_return:x}"
                )
            if not dst_ok:
                raise ReplError(f"__bitmap_andnot {label} dst bytes did not match expected and-not result")
            if not src_ok:
                raise ReplError(f"__bitmap_andnot {label} modified the source bitmap")
            if not mask_ok:
                raise ReplError(f"__bitmap_andnot {label} modified the mask bitmap")
            if not canary_ok:
                raise ReplError(f"__bitmap_andnot {label} modified a canary")

        for name, expected_scan in expected_scans.items():
            observed = _peek_bytes(session, ptrs[name], scan_len)
            observed_after[name] = observed
            unchanged = observed == expected_scan
            checks.append({
                "check": f"bitmap-andnot-{name}-immutability",
                "ok": unchanged,
                "buffer_unchanged": unchanged,
                "canary_preserved": observed[-BITMAP_ANDNOT_CANARY_LEN:] == BITMAP_ANDNOT_CANARY_BYTES,
            })
            if not unchanged:
                raise ReplError(f"__bitmap_andnot modified the owned {name} bitmap buffer")
    finally:
        if kfree_runtime:
            for name, ptr in list(ptrs.items()):
                if ptr and is_kernel_lowmem_pointer(ptr):
                    try:
                        session.call_runtime(kfree_runtime, (ptr,))
                        free_results[name] = True
                    except Exception as exc:  # noqa: BLE001 - cleanup failures must be visible
                        free_results[name] = False
                        free_errors[name] = str(exc)
        session.set_panic_on_oops(1)

    checks.append({
        "check": "bitmap-andnot-case-table",
        "ok": all(bool(case.get("ok")) for case in case_results),
        "case_count": len(case_results),
        "cases": case_results,
    })
    for name in ("src", "partial", "full", "dst"):
        checks.append({
            "check": f"kfree-owned-bitmap-andnot-{name}",
            "ok": free_results.get(name) is True,
            "free_attempted": name in ptrs,
        })
    if free_errors:
        detail = "; ".join(f"{name}: {msg}" for name, msg in sorted(free_errors.items()))
        raise ReplError(f"kfree failed after __bitmap_andnot proof: {detail}")

    passed = all(bool(check.get("ok")) for check in checks)
    summary = {
        "decision": f"a90-repl-live-call-proof-__bitmap_andnot-{'pass' if passed else 'fail'}",
        "ok": passed,
        "target": "__bitmap_andnot",
        "proof_status": "trusted-under-owned-input-contract" if passed else "failed",
        "input_contract": CALL_PROOF_TARGETS["__bitmap_andnot"]["input_contract"],
        "return_contract": CALL_PROOF_TARGETS["__bitmap_andnot"]["return_contract"],
        "alloc_size": alloc_size,
        "bitmap_size_bits": BITMAP_ANDNOT_PROOF_SIZE_BITS,
        "src_bits": list(BITMAP_ANDNOT_SRC_BITS),
        "partial_mask_bits": list(BITMAP_ANDNOT_PARTIAL_MASK_BITS),
        "full_extra_bits": list(BITMAP_ANDNOT_FULL_EXTRA_BITS),
        "case_results": case_results,
        "dst_matches_expected_after_each_case": True,
        "src_and_masks_unchanged_after_calls": True,
        "gfp_kernel": f"0x{gfp:x}",
        "source_evidence": _source_row_evidence(source),
        "call_safety": call_safety,
        "resolutions": _redacted_resolution_set(resolutions),
        "raw_runtime_values_redacted": True,
        "owned_pointer_redacted": True,
        "observed_bytes_redacted": True,
        "checks": checks,
        "function_map_entry": {
            "symbol": "__bitmap_andnot",
            "status": "live-proven",
            "trusted_input_contract": CALL_PROOF_TARGETS["__bitmap_andnot"]["input_contract"],
            "return_contract": CALL_PROOF_TARGETS["__bitmap_andnot"]["return_contract"],
            "observed_return_value": "case-table-zero-positive-and-full-mask-negative",
            "cleanup": "kfree-owned-bitmap-andnot-buffers-ok" if all(free_results.get(name) for name in ("src", "partial", "full", "dst")) else "cleanup-failed",
            "auto_call_policy": "one-target-proof-only-not-mass-call",
        },
    }
    private.update({
        "slide": f"0x{slide:x}",
        "__bitmap_andnot_runtime": f"0x{((target_link + slide) & MASK64):x}",
        "alloc_ptrs": {name: f"0x{ptr:x}" for name, ptr in ptrs.items()},
        "observed_bytes_hex": {
            **{name: observed.hex() for name, observed in observed_after.items()},
            "dst_by_case": {label: data.hex() for label, data in observed_dst_by_case.items()},
        },
        "case_returns": {
            str(case["case"]): str(case["observed_return_value"])
            for case in case_results
        },
        "gfp_components": {key: f"0x{component:x}" for key, component in gfp_components.items()},
    })
    return summary, private


def _run_call_proof___bitmap_or(session: ReplSession,
                                symbols: dict[str, Symbol],
                                image: StaticImage,
                                *,
                                alloc_size: int,
                                source_root: Path,
                                gfp: int,
                                gfp_components: dict[str, int]) -> tuple[dict[str, object], dict[str, object]]:
    bitmap_payloads = {
        "left": BITMAP_OR_LEFT_BYTES,
        "partial": BITMAP_OR_RIGHT_PARTIAL_BYTES,
        "full": BITMAP_OR_RIGHT_FULL_BYTES,
    }
    expected_scans = {
        name: payload + BITMAP_OR_CANARY_BYTES
        for name, payload in bitmap_payloads.items()
    }
    dst_initial_scan = BITMAP_OR_DST_INITIAL_BYTES + BITMAP_OR_CANARY_BYTES
    scan_len = len(dst_initial_scan)
    if alloc_size < scan_len:
        raise ReplError(f"__bitmap_or call-proof alloc_size must be at least {scan_len} bytes")
    if BITMAP_OR_PROOF_SIZE_BITS != len(BITMAP_OR_LEFT_BYTES) * 8:
        raise ReplError("__bitmap_or proof bit size does not match bitmap byte length")
    if any(bit < 0 or bit >= BITMAP_OR_PROOF_SIZE_BITS for bit in BITMAP_OR_LEFT_BITS):
        raise ReplError("__bitmap_or proof set bit is outside the bitmap")
    for label, right_name, nbits in BITMAP_OR_CASES:
        if right_name not in ("partial", "full"):
            raise ReplError(f"__bitmap_or case {label!r} references an unknown right bitmap")
        if not (0 <= nbits <= BITMAP_OR_PROOF_SIZE_BITS):
            raise ReplError(f"__bitmap_or case {label!r} has an invalid nbits")

    source = lookup_source_signature("__bitmap_or", source_root=source_root)
    call_safety = require_call_safety_for_call(
        symbols,
        image,
        "__bitmap_or",
        ("@owned_dst_bitmap", "@owned_left_bitmap", "@owned_right_bitmap", BITMAP_OR_PROOF_SIZE_BITS),
    )
    if call_safety.get("tier") != CALL_PROOF_TARGETS["__bitmap_or"]["expected_tier"]:
        raise ReplError("__bitmap_or call-safety tier is not the expected vetted pointer tier")
    selected = source.get("selected")
    selected_signature = selected.get("signature") if isinstance(selected, dict) else None
    if not source.get("found") or source.get("pointer_arg_indices") != [0, 1, 2]:
        raise ReplError("__bitmap_or source signature does not declare x0/x1/x2 as bitmap pointer arguments")
    if selected_signature != CALL_PROOF_TARGETS["__bitmap_or"]["source_signature"]:
        raise ReplError("__bitmap_or source signature did not select the exported declaration")

    resolutions = {
        "__bitmap_or": resolve_verified(
            symbols,
            image,
            "__bitmap_or",
            purpose="call",
            allow_pre_arg_deref=True,
        ),
        "__kmalloc": resolve_verified(symbols, image, "__kmalloc", purpose="call"),
        "kfree": resolve_verified(symbols, image, "kfree", purpose="call"),
    }
    target_link = require_verified_resolution(resolutions["__bitmap_or"], "call-proof target")
    kmalloc_link = require_verified_resolution(resolutions["__kmalloc"], "call-proof bitmap allocator")
    kfree_link = require_verified_resolution(resolutions["kfree"], "call-proof bitmap cleanup")
    assert_no_precall_x0_pointer_deref(image, kmalloc_link, "__kmalloc")

    static_words = {
        "nlongs-mov": (target_link + 0x00, BITMAP_OR_NLONGS_MOV_WORD),
        "nlongs-add": (target_link + 0x04, BITMAP_OR_NLONGS_ADD_WORD),
        "nlongs-lsr": (target_link + 0x08, BITMAP_OR_NLONGS_LSR_WORD),
        "first-left-load": (target_link + 0x14, BITMAP_OR_FIRST_LEFT_LOAD_WORD),
        "first-right-load": (target_link + 0x18, BITMAP_OR_FIRST_RIGHT_LOAD_WORD),
        "first-orr": (target_link + 0x1C, BITMAP_OR_FIRST_ORR_WORD),
        "first-dst-store": (target_link + 0x28, BITMAP_OR_FIRST_DST_STORE_WORD),
    }
    checks: list[dict[str, object]] = [
        {
            "check": "static-c1-identity",
            "ok": True,
            "target": "__bitmap_or",
            "resolution_method": resolutions["__bitmap_or"].method,
        },
        {
            "check": "static-source-contract",
            "ok": True,
            "signature": selected_signature,
            "pointer_arg_indices": source.get("pointer_arg_indices", []),
        },
        {
            "check": "static-call-safety-contract",
            "ok": True,
            "tier": call_safety.get("tier"),
            "required_valid_pointer_args": call_safety.get("required_valid_pointer_args", {}),
            "bounded_size_bits": BITMAP_OR_PROOF_SIZE_BITS,
        },
    ]
    for label, (vaddr, expected_word) in static_words.items():
        observed_word = image.u32_at_vaddr(vaddr)
        ok = observed_word == expected_word
        checks.append({
            "check": f"static-{label}",
            "ok": ok,
            "expected_word": f"0x{expected_word:08x}",
            "observed_word": f"0x{observed_word:08x}",
        })
        if not ok:
            raise ReplError(
                "__bitmap_or static word mismatch for "
                f"{label}: observed 0x{observed_word:08x}, expected 0x{expected_word:08x}"
            )

    private: dict[str, object] = {}
    ptrs: dict[str, int] = {}
    slide = 0
    kfree_runtime = 0
    free_results: dict[str, bool] = {}
    free_errors: dict[str, str] = {}
    case_results: list[dict[str, object]] = []
    observed_dst_by_case: dict[str, bytes] = {}
    observed_after: dict[str, bytes] = {}

    session.hide()
    session.set_panic_on_oops(0)
    try:
        slide = session.slide()
        if slide & 0xFFF:
            raise ReplError("slide is not page-aligned; refusing to proceed")
        target_runtime = (target_link + slide) & MASK64
        kmalloc_runtime = (kmalloc_link + slide) & MASK64
        kfree_runtime = (kfree_link + slide) & MASK64

        for name, expected_scan in (
            ("left", expected_scans["left"]),
            ("partial", expected_scans["partial"]),
            ("full", expected_scans["full"]),
            ("dst", dst_initial_scan),
        ):
            ptr = session.call_runtime(kmalloc_runtime, (alloc_size, gfp))
            ptr_ok = is_kernel_lowmem_pointer(ptr)
            checks.append({
                "check": f"kmalloc-owned-bitmap-or-{name}",
                "ok": ptr_ok,
                "alloc_size": alloc_size,
                "kernel_lowmem": ptr_ok,
            })
            if not ptr_ok:
                raise ReplError(f"__kmalloc did not return a sane __bitmap_or {name} buffer")
            ptrs[name] = ptr
            _poke_bytes(session, ptr, expected_scan)
            observed = _peek_bytes(session, ptr, scan_len)
            setup_ok = observed == expected_scan
            checks.append({
                "check": f"owned-bitmap-or-{name}-poke-peek",
                "ok": setup_ok,
                "bitmap_size_bits": BITMAP_OR_PROOF_SIZE_BITS,
                "canary_len": BITMAP_OR_CANARY_LEN,
            })
            if not setup_ok:
                raise ReplError(f"owned __bitmap_or {name} bitmap poke/peek mismatch")

        for label, right_name, nbits in BITMAP_OR_CASES:
            _poke_bytes(session, ptrs["dst"], dst_initial_scan)
            reset_dst = _peek_bytes(session, ptrs["dst"], scan_len)
            if reset_dst != dst_initial_scan:
                raise ReplError(f"owned __bitmap_or dst reset mismatch before {label}")

            expected_dst_scan = _bitmap_or_expected(right_name, nbits) + BITMAP_OR_CANARY_BYTES
            _ignored_return = session.call_runtime(
                target_runtime,
                (ptrs["dst"], ptrs["left"], ptrs[right_name], nbits),
            )
            observed_dst = _peek_bytes(session, ptrs["dst"], scan_len)
            observed_left = _peek_bytes(session, ptrs["left"], scan_len)
            observed_right = _peek_bytes(session, ptrs[right_name], scan_len)
            dst_ok = observed_dst == expected_dst_scan
            left_ok = observed_left == expected_scans["left"]
            right_ok = observed_right == expected_scans[right_name]
            canary_ok = (
                observed_dst[-BITMAP_OR_CANARY_LEN:] == BITMAP_OR_CANARY_BYTES
                and observed_left[-BITMAP_OR_CANARY_LEN:] == BITMAP_OR_CANARY_BYTES
                and observed_right[-BITMAP_OR_CANARY_LEN:] == BITMAP_OR_CANARY_BYTES
            )
            observed_dst_by_case[label] = observed_dst
            case_results.append({
                "case": label,
                "right": right_name,
                "nbits": nbits,
                "return_value_ignored": True,
                "observed_return_value_redacted": True,
                "dst_matches_expected": dst_ok,
                "left_unchanged": left_ok,
                "right_unchanged": right_ok,
                "canary_preserved": canary_ok,
                "ok": dst_ok and left_ok and right_ok and canary_ok,
            })
            if not dst_ok:
                raise ReplError(f"__bitmap_or {label} dst bytes did not match expected OR result")
            if not left_ok:
                raise ReplError(f"__bitmap_or {label} modified the left bitmap")
            if not right_ok:
                raise ReplError(f"__bitmap_or {label} modified the right bitmap")
            if not canary_ok:
                raise ReplError(f"__bitmap_or {label} modified a canary")

        for name, expected_scan in expected_scans.items():
            observed = _peek_bytes(session, ptrs[name], scan_len)
            observed_after[name] = observed
            unchanged = observed == expected_scan
            checks.append({
                "check": f"bitmap-or-{name}-immutability",
                "ok": unchanged,
                "buffer_unchanged": unchanged,
                "canary_preserved": observed[-BITMAP_OR_CANARY_LEN:] == BITMAP_OR_CANARY_BYTES,
            })
            if not unchanged:
                raise ReplError(f"__bitmap_or modified the owned {name} bitmap buffer")
    finally:
        if kfree_runtime:
            for name, ptr in list(ptrs.items()):
                if ptr and is_kernel_lowmem_pointer(ptr):
                    try:
                        session.call_runtime(kfree_runtime, (ptr,))
                        free_results[name] = True
                    except Exception as exc:  # noqa: BLE001 - cleanup failures must be visible
                        free_results[name] = False
                        free_errors[name] = str(exc)
        session.set_panic_on_oops(1)

    checks.append({
        "check": "bitmap-or-case-table",
        "ok": all(bool(case.get("ok")) for case in case_results),
        "case_count": len(case_results),
        "cases": case_results,
    })
    for name in ("left", "partial", "full", "dst"):
        checks.append({
            "check": f"kfree-owned-bitmap-or-{name}",
            "ok": free_results.get(name) is True,
            "free_attempted": name in ptrs,
        })
    if free_errors:
        detail = "; ".join(f"{name}: {msg}" for name, msg in sorted(free_errors.items()))
        raise ReplError(f"kfree failed after __bitmap_or proof: {detail}")

    passed = all(bool(check.get("ok")) for check in checks)
    summary = {
        "decision": f"a90-repl-live-call-proof-__bitmap_or-{'pass' if passed else 'fail'}",
        "ok": passed,
        "target": "__bitmap_or",
        "proof_status": "trusted-under-owned-input-contract" if passed else "failed",
        "input_contract": CALL_PROOF_TARGETS["__bitmap_or"]["input_contract"],
        "return_contract": CALL_PROOF_TARGETS["__bitmap_or"]["return_contract"],
        "alloc_size": alloc_size,
        "bitmap_size_bits": BITMAP_OR_PROOF_SIZE_BITS,
        "left_bits": list(BITMAP_OR_LEFT_BITS),
        "partial_right_extra_bits": list(BITMAP_OR_RIGHT_PARTIAL_EXTRA_BITS),
        "full_right_extra_bits": list(BITMAP_OR_RIGHT_FULL_EXTRA_BITS),
        "case_results": case_results,
        "dst_matches_expected_after_each_case": True,
        "left_and_right_bitmaps_unchanged_after_calls": True,
        "gfp_kernel": f"0x{gfp:x}",
        "source_evidence": _source_row_evidence(source),
        "call_safety": call_safety,
        "resolutions": _redacted_resolution_set(resolutions),
        "raw_runtime_values_redacted": True,
        "owned_pointer_redacted": True,
        "observed_bytes_redacted": True,
        "checks": checks,
        "function_map_entry": {
            "symbol": "__bitmap_or",
            "status": "live-proven",
            "trusted_input_contract": CALL_PROOF_TARGETS["__bitmap_or"]["input_contract"],
            "return_contract": CALL_PROOF_TARGETS["__bitmap_or"]["return_contract"],
            "observed_return_value": "void-return-ignored; destination-matched-source1-or-source2-word-coverage",
            "cleanup": "kfree-owned-bitmap-or-buffers-ok" if all(free_results.get(name) for name in ("left", "partial", "full", "dst")) else "cleanup-failed",
            "auto_call_policy": "one-target-proof-only-not-mass-call",
        },
    }
    private.update({
        "slide": f"0x{slide:x}",
        "__bitmap_or_runtime": f"0x{((target_link + slide) & MASK64):x}",
        "alloc_ptrs": {name: f"0x{ptr:x}" for name, ptr in ptrs.items()},
        "observed_bytes_hex": {
            **{name: observed.hex() for name, observed in observed_after.items()},
            "dst_by_case": {label: data.hex() for label, data in observed_dst_by_case.items()},
        },
        "gfp_components": {key: f"0x{component:x}" for key, component in gfp_components.items()},
    })
    return summary, private


def _run_call_proof___bitmap_set(session: ReplSession,
                                 symbols: dict[str, Symbol],
                                 image: StaticImage,
                                 *,
                                 alloc_size: int,
                                 source_root: Path,
                                 gfp: int,
                                 gfp_components: dict[str, int]) -> tuple[dict[str, object], dict[str, object]]:
    initial_scan = BITMAP_SET_INITIAL_BYTES + BITMAP_SET_CANARY_BYTES
    scan_len = len(initial_scan)
    if alloc_size < scan_len:
        raise ReplError(f"__bitmap_set call-proof alloc_size must be at least {scan_len} bytes")
    if BITMAP_SET_PROOF_SIZE_BITS != len(BITMAP_SET_INITIAL_BYTES) * 8:
        raise ReplError("__bitmap_set proof bit size does not match bitmap byte length")
    if any(bit < 0 or bit >= BITMAP_SET_PROOF_SIZE_BITS for bit in BITMAP_SET_INITIAL_BITS):
        raise ReplError("__bitmap_set proof set bit is outside the bitmap")
    for label, start, length in BITMAP_SET_CASES:
        if start < 0 or length < 0 or start + length > BITMAP_SET_PROOF_SIZE_BITS:
            raise ReplError(f"__bitmap_set case {label!r} has an invalid start/len")

    source = lookup_source_signature("__bitmap_set", source_root=source_root)
    call_safety = require_call_safety_for_call(
        symbols,
        image,
        "__bitmap_set",
        ("@owned_bitmap", 0, BITMAP_SET_PROOF_SIZE_BITS),
    )
    if call_safety.get("tier") != CALL_PROOF_TARGETS["__bitmap_set"]["expected_tier"]:
        raise ReplError("__bitmap_set call-safety tier is not the expected vetted pointer tier")
    selected = source.get("selected")
    selected_signature = selected.get("signature") if isinstance(selected, dict) else None
    if not source.get("found") or source.get("pointer_arg_indices") != [0]:
        raise ReplError("__bitmap_set source signature does not declare x0 as the bitmap pointer argument")
    if selected_signature != CALL_PROOF_TARGETS["__bitmap_set"]["source_signature"]:
        raise ReplError("__bitmap_set source signature did not select the exported declaration")

    resolutions = {
        "__bitmap_set": resolve_verified(
            symbols,
            image,
            "__bitmap_set",
            purpose="call",
            allow_pre_arg_deref=True,
        ),
        "__kmalloc": resolve_verified(symbols, image, "__kmalloc", purpose="call"),
        "kfree": resolve_verified(symbols, image, "kfree", purpose="call"),
    }
    target_link = require_verified_resolution(resolutions["__bitmap_set"], "call-proof target")
    kmalloc_link = require_verified_resolution(resolutions["__kmalloc"], "call-proof bitmap allocator")
    kfree_link = require_verified_resolution(resolutions["kfree"], "call-proof bitmap cleanup")
    assert_no_precall_x0_pointer_deref(image, kmalloc_link, "__kmalloc")

    static_words = {
        "lsr-start": (target_link + 0x00, BITMAP_SET_LSR_START_WORD),
        "first-load": (target_link + 0x1C, BITMAP_SET_FIRST_LOAD_WORD),
        "first-orr": (target_link + 0x28, BITMAP_SET_FIRST_ORR_WORD),
        "first-store": (target_link + 0x30, BITMAP_SET_FIRST_STORE_WORD),
        "middle-full-store": (target_link + 0x50, BITMAP_SET_MIDDLE_FULL_STORE_WORD),
        "tail-load": (target_link + 0x6C, BITMAP_SET_TAIL_LOAD_WORD),
        "tail-store": (target_link + 0x80, BITMAP_SET_TAIL_STORE_WORD),
    }
    checks: list[dict[str, object]] = [
        {
            "check": "static-c1-identity",
            "ok": True,
            "target": "__bitmap_set",
            "resolution_method": resolutions["__bitmap_set"].method,
        },
        {
            "check": "static-source-contract",
            "ok": True,
            "signature": selected_signature,
            "pointer_arg_indices": source.get("pointer_arg_indices", []),
        },
        {
            "check": "static-call-safety-contract",
            "ok": True,
            "tier": call_safety.get("tier"),
            "required_valid_pointer_args": call_safety.get("required_valid_pointer_args", {}),
            "bounded_size_bits": BITMAP_SET_PROOF_SIZE_BITS,
        },
    ]
    for label, (vaddr, expected_word) in static_words.items():
        observed_word = image.u32_at_vaddr(vaddr)
        ok = observed_word == expected_word
        checks.append({
            "check": f"static-{label}",
            "ok": ok,
            "expected_word": f"0x{expected_word:08x}",
            "observed_word": f"0x{observed_word:08x}",
        })
        if not ok:
            raise ReplError(
                "__bitmap_set static word mismatch for "
                f"{label}: observed 0x{observed_word:08x}, expected 0x{expected_word:08x}"
            )

    private: dict[str, object] = {}
    ptr = 0
    slide = 0
    kfree_runtime = 0
    free_attempted = False
    free_ok = False
    free_error = ""
    case_results: list[dict[str, object]] = []
    observed_by_case: dict[str, bytes] = {}

    session.hide()
    session.set_panic_on_oops(0)
    try:
        slide = session.slide()
        if slide & 0xFFF:
            raise ReplError("slide is not page-aligned; refusing to proceed")
        target_runtime = (target_link + slide) & MASK64
        kmalloc_runtime = (kmalloc_link + slide) & MASK64
        kfree_runtime = (kfree_link + slide) & MASK64

        ptr = session.call_runtime(kmalloc_runtime, (alloc_size, gfp))
        ptr_ok = is_kernel_lowmem_pointer(ptr)
        checks.append({
            "check": "kmalloc-owned-bitmap-set-buffer",
            "ok": ptr_ok,
            "alloc_size": alloc_size,
            "kernel_lowmem": ptr_ok,
        })
        if not ptr_ok:
            raise ReplError("__kmalloc did not return a sane __bitmap_set buffer")

        _poke_bytes(session, ptr, initial_scan)
        observed_initial = _peek_bytes(session, ptr, scan_len)
        setup_ok = observed_initial == initial_scan
        checks.append({
            "check": "owned-bitmap-set-poke-peek",
            "ok": setup_ok,
            "bitmap_size_bits": BITMAP_SET_PROOF_SIZE_BITS,
            "canary_len": BITMAP_SET_CANARY_LEN,
        })
        if not setup_ok:
            raise ReplError("owned __bitmap_set bitmap poke/peek mismatch")

        for label, start, length in BITMAP_SET_CASES:
            _poke_bytes(session, ptr, initial_scan)
            reset_scan = _peek_bytes(session, ptr, scan_len)
            if reset_scan != initial_scan:
                raise ReplError(f"owned __bitmap_set bitmap reset mismatch before {label}")

            observed_return = session.call_runtime(target_runtime, (ptr, start, length))
            expected_scan = _bitmap_set_expected(start, length) + BITMAP_SET_CANARY_BYTES
            observed = _peek_bytes(session, ptr, scan_len)
            bitmap_ok = observed[:len(BITMAP_SET_INITIAL_BYTES)] == expected_scan[:len(BITMAP_SET_INITIAL_BYTES)]
            canary_ok = observed[-BITMAP_SET_CANARY_LEN:] == BITMAP_SET_CANARY_BYTES
            observed_by_case[label] = observed
            case_results.append({
                "case": label,
                "start": start,
                "len": length,
                "return_value_ignored": True,
                "observed_return_value_redacted": True,
                "bitmap_matches_expected": bitmap_ok,
                "canary_preserved": canary_ok,
                "ok": bitmap_ok and canary_ok,
            })
            if not bitmap_ok:
                raise ReplError(f"__bitmap_set {label} bitmap bytes did not match expected set range")
            if not canary_ok:
                raise ReplError(f"__bitmap_set {label} modified the canary")
            _ = observed_return
    finally:
        if ptr and is_kernel_lowmem_pointer(ptr) and kfree_runtime:
            free_attempted = True
            try:
                session.call_runtime(kfree_runtime, (ptr,))
                free_ok = True
            except Exception as exc:  # noqa: BLE001 - cleanup failures must be visible
                free_error = str(exc)
        session.set_panic_on_oops(1)

    checks.append({
        "check": "bitmap-set-case-table",
        "ok": all(bool(case.get("ok")) for case in case_results),
        "case_count": len(case_results),
        "cases": case_results,
    })
    checks.append({
        "check": "kfree-owned-bitmap-set-buffer",
        "ok": free_ok,
        "free_attempted": free_attempted,
    })
    if free_error:
        raise ReplError(f"kfree failed after __bitmap_set proof: {free_error}")

    passed = all(bool(check.get("ok")) for check in checks)
    summary = {
        "decision": f"a90-repl-live-call-proof-__bitmap_set-{'pass' if passed else 'fail'}",
        "ok": passed,
        "target": "__bitmap_set",
        "proof_status": "trusted-under-owned-input-contract" if passed else "failed",
        "input_contract": CALL_PROOF_TARGETS["__bitmap_set"]["input_contract"],
        "return_contract": CALL_PROOF_TARGETS["__bitmap_set"]["return_contract"],
        "alloc_size": alloc_size,
        "bitmap_size_bits": BITMAP_SET_PROOF_SIZE_BITS,
        "initial_bits": list(BITMAP_SET_INITIAL_BITS),
        "case_results": case_results,
        "bitmap_matches_expected_after_each_case": True,
        "bitmap_canary_preserved_after_each_case": True,
        "gfp_kernel": f"0x{gfp:x}",
        "source_evidence": _source_row_evidence(source),
        "call_safety": call_safety,
        "resolutions": _redacted_resolution_set(resolutions),
        "raw_runtime_values_redacted": True,
        "owned_pointer_redacted": True,
        "observed_bytes_redacted": True,
        "checks": checks,
        "function_map_entry": {
            "symbol": "__bitmap_set",
            "status": "live-proven",
            "trusted_input_contract": CALL_PROOF_TARGETS["__bitmap_set"]["input_contract"],
            "return_contract": CALL_PROOF_TARGETS["__bitmap_set"]["return_contract"],
            "observed_return_value": "void-return-ignored; bitmap-range-case-table-matched",
            "cleanup": "kfree-owned-bitmap-set-buffer-ok" if free_ok else "cleanup-failed",
            "auto_call_policy": "one-target-proof-only-not-mass-call",
        },
    }
    private.update({
        "slide": f"0x{slide:x}",
        "__bitmap_set_runtime": f"0x{((target_link + slide) & MASK64):x}",
        "alloc_ptr": f"0x{ptr:x}",
        "observed_bytes_hex": {
            "initial": initial_scan.hex(),
            "bitmap_by_case": {label: data.hex() for label, data in observed_by_case.items()},
        },
        "gfp_components": {key: f"0x{component:x}" for key, component in gfp_components.items()},
    })
    return summary, private


